const colorImpacto = s.impacto === 'Crítico' ? '#ef4444' : (s.impacto === 'Alto' ? '#f97316' : (s.impacto === 'Medio' ? '#f59e0b' : '#22c55e'));
const badgeTipo = s.tipo === 'Emergencia' ? '🔴' : (s.tipo === 'Mayor' ? '🟠' : (s.tipo === 'Normal' ? '🔵' : '🟢'));

html += '<tr style="background:#f8fafc;">';
