// Registrar nuevo usuario
async function registerUser(email, password) {
  try {
    const userCredential = await firebase.auth().createUserWithEmailAndPassword(email, password);
    console.log('✅ Usuario registrado:', userCredential.user.email);
    showNotification('✅ Registro exitoso. Bienvenido!');
    return userCredential.user;
  } catch (error) {
    console.error('❌ Error al registrar:', error.message);
    showNotification('❌ ' + error.message);
    throw error;
  }
}

// Iniciar sesión existente
async function loginUser(email, password) {
  try {
    const response = await fetch(`${API_URL}/api/auth/login`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ email, password })
    });
    
    const data = await response.json();
    
    if (data.success) {
      localStorage.setItem('authToken', data.token);
      window.authToken = data.token;
      showNotification('✅ Bienvenido!');
      return data.user;
    } else {
      throw new Error(data.error);
    }
  } catch (error) {
    showNotification('❌ ' + error.message);
    throw error;
  }
}

// 👇👇 AÑADE ESTO DESPUÉS DEL LOGIN CON GITHUB/GOOGLE 👇👇
firebase.auth().onAuthStateChanged(async (user) => {
  if (user) {
    // Obtener token de Firebase
    const idToken = await user.getIdToken();
    
    // Enviar a TU backend para obtener un token válido
    const res = await fetch('https://mi-sistema-proyectos-backend-4.onrender.com/api/auth/login', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ idToken })
    });
    
    const data = await res.json();
    if (data.token) {
      // Guardar el token real de tu backend
      localStorage.setItem('authToken', data.token);
      localStorage.setItem('userEmail', user.email);
      
      // ==================== 🔥 NUEVO: Extraer clienteId del token ====================
      try {
        // Decodificar el token JWT (está en formato base64)
        const payload = JSON.parse(atob(data.token.split('.')[1]));
        
        if (payload.clienteId) {
          localStorage.setItem('clienteId', payload.clienteId);
          console.log('✅ ClienteId guardado automáticamente:', payload.clienteId);
        } else {
          console.warn('⚠️ El token no contiene clienteId');
        }
      } catch (e) {
        console.error('❌ Error al decodificar token:', e.message);
      }
      // ==================== FIN NUEVO ====================
      
      // Recargar solo si no estamos en medio de una operación crítica
      if (!window.location.search.includes('payment=success')) {
        location.reload();
      }
    }
  }
});
// Obtener usuario actual
