// 🔍 FUNCIÓN DE DIAGNÓSTICO PARA BURNDOWN
window.diagnosticoBurndown = function() {
  console.clear();
  console.log('🔍 ===== DIAGNÓSTICO BURNDOWN =====');
  
  // 1. Verificar si el botón está funcionando
  console.log('1. ✅ Función showBurnDownChartPremium existe:', typeof window.showBurnDownChartPremium === 'function');
  
  // 2. Verificar si el Gantt está abierto
  const ganttContainer = document.getElementById('premiumExecutiveGantt');
  console.log('2. 📊 Gantt container existe:', !!ganttContainer);
  
  if (ganttContainer) {
    console.log('   • Proyecto:', ganttContainer.dataset.projectName);
    console.log('   • Índice:', ganttContainer.dataset.projectIndex);
    
    // 3. Verificar proyectos y tareas
    const projectIndex = parseInt(ganttContainer.dataset.projectIndex) || currentProjectIndex;
    console.log('3. 📋 Current project index:', projectIndex);
    console.log('   • Total proyectos:', projects.length);
    
    if (projects[projectIndex]) {
      const currentProject = projects[projectIndex];
      console.log('   • Proyecto actual:', currentProject.name);
      console.log('   • Tareas del proyecto:', currentProject.tasks ? currentProject.tasks.length : 0);
      
      if (currentProject.tasks && currentProject.tasks.length > 0) {
        console.log('   • Ejemplo de tarea:', currentProject.tasks[0]);
      }
    }
  }
  
  // 4. Verificar si hay modales abiertos
  console.log('4. 🪟 Modales Burndown abiertos:');
  const modales = document.querySelectorAll('.executive-overlay, #burndownChartContainer, #graficoBurndown');
  console.log('   • Total modales encontrados:', modales.length);
  modales.forEach((modal, i) => {
    console.log(`   ${i + 1}. ${modal.id || modal.className} - Visible: ${isElementVisible(modal)}`);
  });
  
  // 5. Verificar instancias de Chart.js
  console.log('5. 📈 Instancias de Chart.js:');
  console.log('   • burndownChartPremiumInstance:', window.burndownChartPremiumInstance ? 'EXISTE' : 'NO existe');
  console.log('   • burndownChartInstance:', window.burndownChartInstance ? 'EXISTE' : 'NO existe');
  console.log('   • Total instancias Chart:', Chart.instances ? Chart.instances.length : 'N/A');
  
  // 6. Verificar si calculateBurndownFromTasks funciona
  console.log('6. 🧮 Función calculateBurndownFromTasks:');
  console.log('   • Existe:', typeof calculateBurndownFromTasks === 'function');
  
  if (typeof calculateBurndownFromTasks === 'function' && ganttContainer) {
    const projectIndex = parseInt(ganttContainer.dataset.projectIndex) || currentProjectIndex;
    if (projects[projectIndex] && projects[projectIndex].tasks) {
      try {
        const testData = calculateBurndownFromTasks(projects[projectIndex].tasks);
        console.log('   • Datos calculados:', testData);
        console.log('   • Semanas:', testData.semanas.length);
        console.log('   • Datos ideal:', testData.trabajoIdeal);
        console.log('   • Datos real:', testData.trabajoReal);
      } catch (e) {
        console.log('   • ERROR calculando:', e.message);
      }
    }
  }
  
  console.log('🔍 ===== FIN DIAGNÓSTICO =====');
  
  function isElementVisible(el) {
    return !!(el.offsetWidth || el.offsetHeight || el.getClientRects().length);
  }
};

