// 🔒 PUNTOS BASE POR TAREA (no depende de UI)
function getTaskPoints(task) {
 // Usar storyPoints si existe, sino 1 punto por defecto
  return Number(task.storyPoints) || 1;
}


// 🔥 Cálculo base de puntos del proyecto (SAFE)
function calculateProjectPoints(tasks) {
  let total = 0;
  let burned = 0;

  tasks.forEach(task => {
    const points = getTaskPoints(task);
    total += points;

    if (task.status === 'completed') {
      burned += points;
    } else if (task.status === 'inProgress') {
      burned += points * 0.5;
    }
  });

  // 🔥 Regla ejecutiva: 100% completado = 0 restante
  const allCompleted = tasks.length > 0 && tasks.every(t => t.status === 'completed');
  if (allCompleted) {
    burned = total;
  }

  return {
    totalSP: total,
    burnedSP: burned,
    remainingSP: Math.max(0, Math.round((total - burned) * 100) / 100)
  };
}

// 🔓 Exponer solo para pruebas por consola
window.calculateProjectPoints = calculateProjectPoints;



// 🔥 VERSIÓN MEJORADA: Burn diario basado en estado ACTUAL de tareas
function calculateDailyBurnFromHistory(tasks) {
  const daily = {};

  tasks.forEach(task => {
    if (task.status === 'completed') {
      // Buscar CUÁNDO se completó por última vez
      const completionHistory = (task.history || [])
        .filter(h => h.to === 'completed')
        .sort((a, b) => new Date(b.date) - new Date(a.date)); // Más reciente primero
      
      if (completionHistory.length > 0) {
        const lastCompletion = completionHistory[0];
        const day = lastCompletion.date.split('T')[0];
        const points = getTaskPoints(task);
        daily[day] = (daily[day] || 0) + points;
      }
    }
  });

  console.log('🔥 Burn diario MEJORADO:', daily);
  return daily;
}


