function renderChartWithRetry(attempt) {
  if (attempt > 3) {
    console.warn('❌ No se pudo renderizar el burndown');
    return;
  }

  setTimeout(() => {
    console.log(`🔄 Intentando renderizar gráfico (intento ${attempt}/3)...`);

    renderBurndownChartPremium(burndownData);

    setTimeout(() => {
      if (!window.burndownChartInstance) {
        console.log('⚠️ Gráfico no creado, reintentando...');
        renderChartWithRetry(attempt + 1);
      }
    }, 500);

  }, 200 * attempt);
}

