// 🔥 FUNCIONES AUXILIARES
function getProjectStatusAnalysis(burndownData, tasks) {
  const efficiency = parseFloat(burndownData.efficiency);
  const criticalPending = tasks.filter(t => t.critical && (t.progress || 0) < 100).length;
  
  if (efficiency >= 100 && criticalPending === 0) {
    return '✅ PROYECTO EN CAMINO - Excelente rendimiento. Todas las métricas están en verde. El equipo está superando las expectativas y las tareas críticas están bajo control.';
  } else if (efficiency >= 80) {
    return '🟡 PROYECTO EN RIESGO MODERADO - El rendimiento es aceptable pero hay áreas de mejora. ' + 
           (criticalPending > 0 ? `Existen ${criticalPending} tareas críticas pendientes que requieren atención.` : '');
  } else {
    return '🔴 PROYECTO EN RIESGO ALTO - Se requiere intervención ejecutiva. ' +
           `La eficiencia está en ${efficiency}% (debajo del 80% objetivo). ` +
           (criticalPending > 0 ? `${criticalPending} tareas críticas están pendientes. ` : '') +
           'Se recomienda revisar recursos y planificación.';
  }
}

function getRecommendations(burndownData, tasks) {
  const recommendations = [];
  const efficiency = parseFloat(burndownData.efficiency);
  const criticalPending = tasks.filter(t => t.critical && (t.progress || 0) < 100).length;
  
  if (efficiency < 80) {
    recommendations.push('Revisar asignación de recursos del equipo');
    recommendations.push('Considerar extensión de plazo o reducción de alcance');
  }
  
  if (criticalPending > 0) {
    recommendations.push(`Priorizar las ${criticalPending} tareas críticas pendientes`);
    recommendations.push('Asignar recursos senior a tareas críticas');
  }
  
  if (burndownData.scopeCreep[burndownData.scopeCreep.length - 1] > 0) {
    recommendations.push('Congelar cambios de alcance hasta recuperar cronograma');
  }
  
  if (recommendations.length === 0) {
    recommendations.push('Mantener el ritmo actual - El proyecto va por buen camino');
  }
  
  return recommendations;
}

