    const datasets = [];

    // Línea Ideal
    datasets.push({
      label: 'Línea Ideal',
      data: data.trabajoIdeal,
      borderColor: '#2ecc71',
      borderWidth: 3,
      fill: false,
      tension: 0.1,
      pointRadius: 0
    });

    // Progreso Real
