function calculateScheduleForecast(tasks) {
  if (!tasks || !tasks.length) return null;

  const series = buildEVMSeriesFromTasks(tasks);
  const evm = calculateEVMRealFromTasks(tasks);

  if (!series || !series.dates || series.dates.length < 2 || !evm || !evm.SPI) {
    return null;
  }

  const startDate = new Date(series.dates[0]);
  const plannedEndDate = new Date(series.dates[series.dates.length - 1]);

  const plannedDurationMs = plannedEndDate - startDate;

  const forecastDurationMs =
    evm.SPI > 0 ? plannedDurationMs / evm.SPI : plannedDurationMs;

  const forecastEndDate = new Date(
    startDate.getTime() + forecastDurationMs
  );

  const daysAhead = Math.round(
    (plannedEndDate - forecastEndDate) / (1000 * 60 * 60 * 24)
  );

  return {
    startDate,
    plannedEndDate,
    forecastEndDate,
    SPI: evm.SPI,
    daysAhead
  };
}




// ===============================
// 📈 EVM REAL BASADO EN HORAS - VERSIÓN CORREGIDA
// ===============================

function calculateEVMRealFromTasks(tasks) {
  console.log('🧮 [EVM CANÓNICO] Calculando métricas reales');

  if (!tasks || tasks.length === 0) {
    console.warn('⚠️ No hay tareas');
    return null;
  }

  let EV = 0; // Earned Value
  let AC = 0; // Actual Cost
  let PV = 0; // Planned Value
  let BAC = 0; // Budget at Completion

  console.log('📊 ANALIZANDO ' + tasks.length + ' TAREAS:');

  // ==================== PASO 1: BAC (BASELINE TOTAL, INMUTABLE) ====================
  tasks.forEach(task => {
    const estimated = Number(task.estimatedTime) || 0;
    BAC += estimated;
  });

  console.log('✅ BAC (Presupuesto total aprobado):', BAC, 'h');

  // ==================== PASO 2: PV (VALOR PLANIFICADO A LA FECHA) ====================
  // En tu sistema actual NO manejas fechas → PV = BAC
  PV = BAC;

  console.log('✅ PV (Valor planificado a la fecha):', PV, 'h');

  // ==================== PASO 3: AC (COSTO REAL) ====================
  tasks.forEach(task => {
    const actual =
      Number(task.actualTime) ||
      Number(task.timeLogged) ||
      Number(task.hoursLogged) ||
      0;

    AC += actual;

    console.log(`   "${task.name}": AC = ${actual}h`);
  });

  // ==================== PASO 4: EV (VALOR GANADO) ====================
  // ¡¡¡¡¡CORRECCIÓN PRINCIPAL AQUÍ!!!!!
  tasks.forEach(task => {
    const estimated = Number(task.estimatedTime) || 0;
    const actualHours =
      Number(task.actualTime) ||
      Number(task.timeLogged) ||
      Number(task.hoursLogged) ||
      0;

    let progress = 0;

    // ✅ Regla 1: completado = 100%
    if (task.status === 'completed') {
      progress = 1;
      console.log(`   "${task.name}": completada → 100%`);
    }
    // ✅ Regla 2: en progreso → proporcional REAL
    // ✅ Regla NUEVA: rezagado/overdue/retrasado → también proporcional REAL
    else if (
      (task.status === 'inProgress' || 
       task.status === 'rezagado' || 
       task.status === 'overdue' || 
       task.status === 'retrasado') && 
      estimated > 0
    ) {
      progress = Math.min(1, actualHours / estimated);
      console.log(
        `   "${task.name}": ${actualHours}/${estimated}h (${task.status}) → ${(progress * 100).toFixed(0)}%`
      );
    }
    // ✅ Regla 3: pendiente → 0%
    else {
      progress = 0;
      console.log(`   "${task.name}": ${task.status} → 0%`);
    }

    const taskEV = estimated * progress;
    EV += taskEV;
  });

  // ==================== PASO 5: MÉTRICAS EVM ====================
  const CPI = AC > 0 ? EV / AC : 1;
  const SPI = PV > 0 ? EV / PV : 1;

  const CV = EV - AC;
  const SV = EV - PV;

  // ==================== PASO 6: PRONÓSTICO (PMBOK ESCENARIO B) ====================
  // El resto del trabajo se ejecuta según lo planificado
  const EAC = AC + (BAC - EV);
  const ETC = BAC - EV;
  const VAC = BAC - EAC;

  const result = {
    // Valores base
    PV: Number(PV.toFixed(2)),
    EV: Number(EV.toFixed(2)),
    AC: Number(AC.toFixed(2)),
    BAC: Number(BAC.toFixed(2)),

    // Índices
    CPI: Number(CPI.toFixed(2)),
    SPI: Number(SPI.toFixed(2)),

    // Varianzas
    CV: Number(CV.toFixed(2)),
    SV: Number(SV.toFixed(2)),

    // Pronóstico
    EAC: Number(EAC.toFixed(2)),
    ETC: Number(ETC.toFixed(2)),
    VAC: Number(VAC.toFixed(2)),

    // Info adicional
    totalTasks: tasks.length,
    completedTasks: tasks.filter(t => t.status === 'completed').length,
    inProgressTasks: tasks.filter(t => t.status === 'inProgress').length,
    overdueTasks: tasks.filter(t => 
      t.status === 'rezagado' || 
      t.status === 'overdue' || 
      t.status === 'retrasado'
    ).length
  };

  console.log('📈 RESULTADOS EVM DEFINITIVOS:');
  console.log('   PV:', result.PV, 'h');
  console.log('   EV:', result.EV, 'h');
  console.log('   AC:', result.AC, 'h');
  console.log('   BAC:', result.BAC, 'h');
  console.log('   CPI:', result.CPI);
  console.log('   SPI:', result.SPI);
  console.log('   CV:', result.CV, 'h');
  console.log('   SV:', result.SV, 'h');
  console.log('   EAC:', result.EAC, 'h');
  console.log('   ETC:', result.ETC, 'h');
  console.log('   VAC:', result.VAC, 'h');

  return result;
}







// Función para generar recomendaciones EVM
function generateEVMRecommendations(evmData) {
  let recommendations = '<ul style="margin: 0; padding-left: 20px;">';
  
  if (evmData.cpi < 0.9) {
    recommendations += '<li style="margin-bottom: 10px;">🔴 <strong>Revisar costos urgentemente:</strong> El CPI es bajo (' + evmData.cpi.toFixed(2) + '), hay sobrecostos significativos</li>';
  } else if (evmData.cpi < 1.0) {
    recommendations += '<li style="margin-bottom: 10px;">🟡 <strong>Controlar costos:</strong> El CPI (' + evmData.cpi.toFixed(2) + ') indica ligero sobrecosto</li>';
  } else {
    recommendations += '<li style="margin-bottom: 10px;">✅ <strong>Costos bajo control:</strong> Excelente CPI (' + evmData.cpi.toFixed(2) + ')</li>';
  }
  
  if (evmData.spi < 0.9) {
    recommendations += '<li style="margin-bottom: 10px;">🔴 <strong>Acelerar cronograma:</strong> El SPI es bajo (' + evmData.spi.toFixed(2) + '), hay retraso significativo</li>';
  } else if (evmData.spi < 1.0) {
    recommendations += '<li style="margin-bottom: 10px;">🟡 <strong>Monitorear fechas:</strong> El SPI (' + evmData.spi.toFixed(2) + ') indica ligero retraso</li>';
  } else {
    recommendations += '<li style="margin-bottom: 10px;">✅ <strong>Cronograma en tiempo:</strong> Buen SPI (' + evmData.spi.toFixed(2) + ')</li>';
  }
  
  if (evmData.cv < 0) {
    recommendations += '<li style="margin-bottom: 10px;">💰 <strong>Reducir costos:</strong> Varianza de costo negativa ($' + Math.abs(evmData.cv).toLocaleString() + ')</li>';
  }
  
  if (evmData.sv < 0) {
    recommendations += '<li style="margin-bottom: 10px;">📅 <strong>Recuperar tiempo:</strong> Varianza de tiempo negativa ($' + Math.abs(evmData.sv).toLocaleString() + ')</li>';
  }
  
  // Recomendación general
  if (evmData.cpi >= 1.0 && evmData.spi >= 1.0) {
    recommendations += '<li>🎯 <strong>Proyecto saludable:</strong> Mantener el ritmo actual</li>';
  } else if (evmData.cpi < 0.9 || evmData.spi < 0.9) {
    recommendations += '<li>⚠️ <strong>Revisión ejecutiva necesaria:</strong> Considerar ajustes de alcance o recursos</li>';
  } else {
    recommendations += '<li>📊 <strong>Monitoreo continuo:</strong> Seguir métricas semanalmente</li>';
  }
  
  recommendations += '</ul>';
  
  return recommendations;
}

function renderEVMChart(evm) {
  const canvas = document.getElementById('evmChartCanvas');
  if (!canvas) {
    console.warn('❌ Canvas EVM no encontrado');
    return;
  }

  const ctx = canvas.getContext('2d');

  if (window.evmChartInstance) {
    window.evmChartInstance.destroy();
  }

  // 🔥 MODO COSTOS → BARRAS
  if (window.__EVM_MODE__ === 'costs') {
    console.log('📊 Renderizando gráfico EVM de COSTOS');

    window.evmChartInstance = new Chart(ctx, {
      type: 'bar',
      data: {
        labels: ['PV', 'EV', 'AC', 'BAC'],
        datasets: [{
          label: 'Costos ($)',
          data: [evm.PV, evm.EV, evm.AC, evm.BAC],
          backgroundColor: ['#3b82f6', '#10b981', '#ef4444', '#f59e0b']
        }]
      },
      options: {
        responsive: true,
        plugins: {
          legend: { labels: { color: '#fff' } }
        },
        scales: {
          x: { ticks: { color: '#cbd5e1' } },
          y: { ticks: { color: '#cbd5e1' } }
        }
      }
    });

    return;
  }

  // ⏱️ MODO HORAS → LÍNEAS
  console.log('📈 Renderizando gráfico EVM de HORAS');
  renderEVMChartHours(evm);
}
    
  


function renderEVMChartHours(series) {
  console.log('📈 Renderizando gráfico EVM de HORAS...');

  const canvas = document.getElementById('evmChartCanvas');
  if (!canvas) {
    console.error('❌ Canvas EVM no encontrado');
    return;
  }

  const ctx = canvas.getContext('2d');

  if (window.evmChartInstance) {
    window.evmChartInstance.destroy();
  }

  canvas.width  = canvas.offsetWidth || 800;
  canvas.height = canvas.offsetHeight || 300;

  window.evmChartInstance = new Chart(ctx, {
    type: 'line',
    data: {
      labels: series.dates || [],
      datasets: [
        {
          label: 'PV (Horas)',
          data: series.PV || [],
          borderColor: '#3b82f6',
          borderWidth: 3,
          fill: false
        },
        {
          label: 'EV (Horas)',
          data: series.EV || [],
          borderColor: '#10b981',
          borderWidth: 3,
          fill: false
        },
        {
          label: 'AC (Horas)',
          data: series.AC || [],
          borderColor: '#ef4444',
          borderWidth: 3,
          borderDash: [5, 5],
          fill: false
        }
      ]
    },
    options: {
      responsive: false,
      maintainAspectRatio: false
    }
  });

  console.log('✅ Gráfico EVM HORAS renderizado');
}







