// Función auxiliar para convertir hex a RGB
function hexToRgb(hex) {
  // Eliminar el # si existe
  hex = hex.replace('#', '');
  
  // Convertir a RGB
  const r = parseInt(hex.substring(0, 2), 16);
  const g = parseInt(hex.substring(2, 4), 16);
  const b = parseInt(hex.substring(4, 6), 16);
  
  return { r, g, b };
}

// Función para obtener color según estado
function getStatusColor(status) {
  const colors = {
    'completed': '#10b981',
    'inProgress': '#3b82f6',
    'pending': '#f59e0b',
    'overdue': '#ef4444'
  };
  return colors[status] || '#94a3b8';
}

// Función para generar recomendaciones
function generateRecommendations(project) {
  const recommendations = [];
  const completed = project.tasks.filter(t => t.status === 'completed').length;
  const total = project.tasks.length;
  const progress = total > 0 ? Math.round((completed / total) * 100) : 0;
  const criticalTasks = project.tasks.filter(t => t.critical).length;
  
  if (progress < 50) {
    recommendations.push('Revisar asignación de recursos del equipo');
    recommendations.push('Considerar extensión de plazo o reducción de alcance');
    recommendations.push('Priorizar tareas críticas inmediatamente');
  } else if (progress < 80) {
    recommendations.push('Mantener reuniones de seguimiento semanales');
    recommendations.push('Monitorear tareas críticas de cerca');
    recommendations.push('Actualizar estimaciones de tiempo restante');
  } else {
    recommendations.push('Mantener el ritmo actual de trabajo');
    recommendations.push('Documentar lecciones aprendidas');
    recommendations.push('Planificar fase de cierre del proyecto');
  }
  
  if (criticalTasks > 0) {
    recommendations.push(`Asignar recursos senior a las ${criticalTasks} tareas críticas`);
  }
  
  const overdueTasks = project.tasks.filter(t => t.status === 'overdue').length;
  if (overdueTasks > 0) {
    recommendations.push(`Revisar urgentemente las ${overdueTasks} tareas atrasadas`);
  }
  
  return recommendations;
}
// ========== FUNCIONES AUXILIARES ==========
function generateTeamDistributionData(tasks) {
  const members = {};
  tasks.forEach(task => {
    const assignee = task.assignee || 'Sin asignar';
    if (!members[assignee]) {
      members[assignee] = {
        name: assignee,
        taskCount: 0,
        totalEstimatedTime: 0,
        totalLoggedTime: 0
      };
    }
    members[assignee].taskCount++;
    members[assignee].totalEstimatedTime += task.estimatedTime || 0;
    members[assignee].totalLoggedTime += task.timeLogged || 0;
  });
  
  return Object.values(members);
}

// ========== ANÁLISIS RÁPIDO - VERSIÓN DEL MENÚ LATERAL ==========
window.runAIAnalysisPremium = function() {
  console.log('⚡ EJECUTANDO ANÁLISIS RÁPIDO...');
  
  // Verificar si hay un Gantt activo
  const ganttContainer = document.getElementById('premiumExecutiveGantt');
  if (!ganttContainer) {
    console.warn('⚠️ No se encontró el contenedor Gantt');
    // Intentar crear uno si no existe
    if (typeof createCompleteGanttForCurrentProject === 'function') {
      createCompleteGanttForCurrentProject();
      setTimeout(() => {
        runAIAnalysisPremium(); // Reintentar después de crear
      }, 1000);
    } else {
      showNotification('⚠️ Abre el Gantt Ejecutivo primero');
    }
    return;
  }
  
  // Obtener proyecto actual
  const projectIndex = parseInt(ganttContainer.dataset.projectIndex) || currentProjectIndex;
  if (!projects || !projects[projectIndex]) {
    showNotification('❌ No hay proyectos cargados');
    return;
  }
  
  const project = projects[projectIndex];
  const tasks = project?.tasks || [];
  
  if (!tasks || tasks.length === 0) {
    showNotification('📝 No hay tareas para analizar');
    return;
  }
  
  console.log(`📊 Analizando ${tasks.length} tareas del proyecto: ${project.name}`);
  
  // Análisis rápido (métricas clave)
  const quickAnalysis = performQuickAnalysis(tasks);
  
  // Mostrar resultados en un overlay flotante
  showQuickAnalysisOverlay(quickAnalysis, project.name);
};

// ========== FUNCIÓN DE ANÁLISIS RÁPIDO ==========
function performQuickAnalysis(tasks) {
  console.log('🧮 Calculando análisis rápido...');
  
  const total = tasks.length;
  const completed = tasks.filter(t => t.status === 'completed').length;
  
  // Detección mejorada de tareas críticas
  const critical = tasks.filter(task => {
    if (task.critical === true) return true;
    if (task.priority === 'alta' || task.priority === 'high') return true;
    if (task.status === 'overdue') return true;
    
    // Verificar por fecha cercana al deadline
    if (task.deadline) {
      try {
        const deadline = new Date(task.deadline);
        const today = new Date();
        const daysDiff = Math.ceil((deadline - today) / (1000 * 60 * 60 * 24));
        if (daysDiff <= 3 && task.status !== 'completed') return true;
      } catch (e) {
        console.warn('Error parseando fecha:', e);
      }
    }
    
    return false;
  }).length;
  
  const inProgress = tasks.filter(t => t.status === 'inProgress').length;
  const pending = tasks.filter(t => t.status === 'pending').length;
  
  const completionRate = total > 0 ? (completed / total) * 100 : 0;
  
  // Determinar estado del proyecto
  let status, statusColor, statusIcon, message;
  
  if (completionRate >= 80) {
    status = 'EXCELENTE';
    statusColor = '#2ecc71';
    statusIcon = '✅';
    message = 'El proyecto avanza a muy buen ritmo. Mantén el enfoque actual.';
  } else if (completionRate >= 50) {
    status = 'EN CAMINO';
    statusColor = '#3498db';
    statusIcon = '📈';
    message = 'Progreso constante. Algunas áreas podrían optimizarse.';
  } else if (completionRate >= 30) {
    status = 'ATENCIÓN';
    statusColor = '#f39c12';
    statusIcon = '⚠️';
    message = 'Progreso lento. Considera revisar asignaciones y prioridades.';
  } else {
    status = 'RIESGO';
    statusColor = '#e74c3c';
    statusIcon = '🚨';
    message = 'Progreso insuficiente. Se requiere intervención inmediata.';
  }
  
  // Recomendación principal basada en el análisis
  let recommendedAction;
  
  if (critical > 0 && completed < total * 0.3) {
    recommendedAction = `Enfócate en las ${critical} tarea${critical !== 1 ? 's' : ''} crítica${critical !== 1 ? 's' : ''} primero`;
  } else if (inProgress > total * 0.6) {
    recommendedAction = 'Reduce tareas en progreso para mejorar el enfoque del equipo';
  } else if (pending > total * 0.5) {
    recommendedAction = 'Muchas tareas pendientes - considera asignar más recursos';
  } else if (completionRate < 50) {
    recommendedAction = 'Revisa las tareas pendientes y reasigna prioridades';
  } else {
    recommendedAction = 'Continúa con el plan actual - buen trabajo del equipo';
  }
  
  return {
    total,
    completed,
    critical,
    inProgress,
    pending,
    completionRate: Math.round(completionRate),
    status,
    statusColor,
    statusIcon,
    message,
    recommendedAction,
    timestamp: new Date().toISOString()
  };
}






