function renderCalendar() {
    console.log('📅 Renderizando calendario con barras de duración...');
    
    const calendarEl = document.getElementById('calendar');
    if (!calendarEl) {
        console.error('❌ No se encuentra el elemento calendar');
        return;
    }

    // Destruir instancia anterior si existe
    if (window.calendarInstance) {
        window.calendarInstance.destroy();
        window.calendarInstance = null;
    }

    // Limpiar el contenedor
    calendarEl.innerHTML = '';

    // Obtener eventos
    const events = getFilteredCalendarTasks();
    console.log('📊 Eventos a agregar:', events.length);

    // Configurar FullCalendar
    const calendar = new FullCalendar.Calendar(calendarEl, {
        initialView: 'dayGridMonth',
        headerToolbar: {
            left: 'prev,next today',
            center: 'title',
            right: 'dayGridMonth,timeGridWeek,timeGridDay'
        },
        locale: 'es',
        // 👇 AGREGAR ESTAS DOS LÍNEAS 👇
        showNonCurrentDates: false,  // Oculta días de otros meses
        fixedWeekCount: false,        // Ajusta altura según semanas reales
        // 👆 HASTA AQUÍ 👆
        editable: true,
        selectable: true,
        dayMaxEvents: 3,
dayMaxEventRows: true,
        displayEventTime: false,
        eventDisplay: 'block',
        events: events,
        
        dateClick: function(info) {
            console.log('📅 Click en día:', info.dateStr);
            openTaskModalWithDate(info.dateStr);
        },
        
        eventClick: function(info) {
            const taskId = info.event.extendedProps?.taskId;
            const project = projects[currentProjectIndex];
            const task = project?.tasks?.find(t => t.id == taskId);
            if (task && typeof showTaskDetails === 'function') {
                showTaskDetails(task);
            }
        },
        
        eventDidMount: function(info) {
            const el = info.el;
            const props = info.event.extendedProps;
            
            el.style.cursor = 'pointer';
            el.style.transition = 'all 0.2s ease';
            el.style.display = 'block';
            el.style.width = '100%';
            el.style.margin = '2px 0';
            
            if (props && props.tooltipData) {
                el.addEventListener('mouseenter', function(e) {
                    this.style.transform = 'translateY(-2px) scale(1.02)';
                    this.style.zIndex = '100';
                    this.style.boxShadow = '0 8px 20px rgba(139, 92, 246, 0.3)';
                    window.showCalendarTooltip(e, props.tooltipData);
                });
                
                el.addEventListener('mouseleave', function() {
                    this.style.transform = 'none';
                    this.style.zIndex = '';
                    this.style.boxShadow = '';
                    window.hideCalendarTooltip();
                });
            }
        },
        
        eventChange: function(info) {
            console.log('Evento modificado:', info.event);
            updateTaskFromCalendar(info.event);
        }
    });

    calendar.render();
    
    // Guardar referencia global
    window.calendarInstance = calendar;
    
    // 🔥 APLICAR ESTILOS A LOS DÍAS DE LA SEMANA DESPUÉS DE RENDERIZAR
    setTimeout(() => {
        applyCalendarHeaderStyles();
    }, 100);
    
    // Verificar eventos después de renderizar
    setTimeout(() => {
        const eventsAfter = window.calendarInstance.getEvents();
        console.log('✅ Eventos después de renderizar:', eventsAfter.length);
        if (eventsAfter.length > 0) {
            console.log('📅 Primer evento:', eventsAfter[0].title, 
                        'inicio:', eventsAfter[0].startStr, 
                        'fin:', eventsAfter[0].endStr);
        }
    }, 500);
    
    console.log('✅ Calendario renderizado con barras de duración');
    return calendar;
}
// 🔥 FUNCIÓN PARA APLICAR ESTILOS AL HEADER DEL CALENDARIO (DÍAS DE LA SEMANA)
let _calendarStylesRetries = 0;
const MAX_CALENDAR_RETRIES = 10;

function applyCalendarHeaderStyles() {
    // Si la vista calendario no está activa, no hacemos nada y reiniciamos contador
    const calendarView = document.getElementById('calendarView');
    if (!calendarView || !calendarView.classList.contains('active')) {
        console.log('📅 Vista calendario inactiva, cancelando estilos');
        _calendarStylesRetries = 0;
        return;
    }

    console.log('🎨 Aplicando estilos al header del calendario...');
    
    // Buscar todos los elementos de días de la semana
    const headerCells = document.querySelectorAll('.fc-col-header-cell');
    const headerTexts = document.querySelectorAll('.fc-col-header-cell-cushion');
    
    if (headerCells.length > 0) {
        headerCells.forEach(cell => {
            // Aplicar estilos de fondo
            cell.style.background = 'linear-gradient(135deg, #1e293b, #0f172a)';
            cell.style.color = 'white';
            cell.style.padding = '12px 0';
            cell.style.borderBottom = '2px solid #8b5cf6';
            
            // Guardar referencia para evitar duplicar eventos
            if (!cell.hasAttribute('data-styled')) {
                cell.setAttribute('data-styled', 'true');
                
                // Efecto hover
                cell.addEventListener('mouseenter', function() {
                    this.style.background = 'linear-gradient(135deg, #2d3a4f, #1e2a3a)';
                    this.style.cursor = 'pointer';
                });
                
                cell.addEventListener('mouseleave', function() {
                    this.style.background = 'linear-gradient(135deg, #1e293b, #0f172a)';
                });
            }
        });
        
        console.log(`✅ Estilos aplicados a ${headerCells.length} celdas de días`);
        _calendarStylesRetries = 0; // reiniciamos contador tras éxito
    } else {
        if (_calendarStylesRetries >= MAX_CALENDAR_RETRIES) {
            console.warn(`❌ No se pudo aplicar estilos al calendario después de ${MAX_CALENDAR_RETRIES} intentos`);
            return;
        }
        _calendarStylesRetries++;
        console.warn(`⚠️ No se encontraron celdas de días, reintentando (${_calendarStylesRetries}/${MAX_CALENDAR_RETRIES})...`);
        setTimeout(applyCalendarHeaderStyles, 500);
        return;
    }
    
    // Aplicar estilos al texto
    if (headerTexts.length > 0) {
        headerTexts.forEach(text => {
            text.style.color = '#e2e8f0';
            text.style.fontWeight = '600';
            text.style.fontSize = '14px';
        });
    }
}
// 🔥 OBSERVADOR PARA APLICAR ESTILOS CUANDO CAMBIA LA VISTA O EL MES
function setupCalendarHeaderObserver() {
    console.log('👁️ Configurando observador para el header del calendario...');
    
    const observer = new MutationObserver(function(mutations) {
        // Solo aplicar si la vista calendario está activa
        const calendarView = document.getElementById('calendarView');
        if (calendarView && calendarView.classList.contains('active')) {
            setTimeout(() => {
                applyCalendarHeaderStyles();
            }, 50);
        }
    });    
    // Observar cambios en el contenedor del calendario
    const calendarContainer = document.getElementById('calendar');
    if (calendarContainer) {
        observer.observe(calendarContainer, { childList: true, subtree: true });
        console.log('✅ Observador del calendario activado');
    }
    
    // Aplicar estilos iniciales
    setTimeout(applyCalendarHeaderStyles, 200);
}

