// ================================================

function getFilteredCalendarTasks() {
    const assignee = document.getElementById('filterAssigneeCalendar')?.value.trim();
    const priority = document.getElementById('filterPriorityCalendar')?.value;
    const status = document.getElementById('filterStatusCalendar')?.value;

    const tasks = projects[currentProjectIndex]?.tasks || [];
    console.log('📅 Tareas para calendario:', tasks.length);

    const filteredTasks = tasks
        .filter(task => {
            const taskAssignee = task.assignee?.trim() || '';
            const taskPriority = task.priority || '';
            const taskStatus = task.status || '';

            const matchAssignee = !assignee || taskAssignee === assignee;
            const matchPriority = !priority || taskPriority === priority;
            const matchStatus = !status || taskStatus === status;

            return matchAssignee && matchPriority && matchStatus;
        })
        .map(task => {
            // Determinar color según estado
            const statusColors = {
                'pending': '#f1c40f',
                'inProgress': '#008090',
                'completed': '#2ecc71',
                'overdue': '#e74c3c'
            };

            // Calcular días restantes
            const today = new Date();
            today.setHours(0, 0, 0, 0);
            let daysRemaining = null;
            let isOverdue = false;

            if (task.deadline) {
                const deadlineDate = new Date(task.deadline);
                deadlineDate.setHours(0, 0, 0, 0);
                const diffTime = deadlineDate - today;
                const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
                daysRemaining = diffDays;
                isOverdue = diffDays < 0 && task.status !== 'completed';
            }

            // CORRECCIÓN: Asegurar que startDate y endDate sean válidas
            let startDate = task.startDate;
            let endDate = task.deadline;
            
            // Si no hay startDate, usar hoy
            if (!startDate) {
                startDate = new Date().toISOString().split('T')[0];
                console.log(`⚠️ Tarea "${task.name}" sin startDate, usando hoy: ${startDate}`);
            }
            
            // Si no hay endDate, usar startDate + 1 día
            if (!endDate) {
                endDate = startDate;
                console.log(`⚠️ Tarea "${task.name}" sin deadline, usando: ${endDate}`);
            }
            
            // CORRECCIÓN CRÍTICA: FullCalendar necesita que startDate sea MENOR que endDate
            // Si startDate es mayor que endDate, intercambiarlos
            if (startDate > endDate) {
                console.warn(`⚠️ Tarea "${task.name}" tiene startDate (${startDate}) > deadline (${endDate}), intercambiando...`);
                [startDate, endDate] = [endDate, startDate];
            }
            
            // Para eventos de un solo día, FullCalendar funciona mejor con solo start
            let eventStart = startDate;
            let eventEnd = null;
            
            // Si es el mismo día, no usar end
            if (startDate === endDate) {
                eventEnd = null;
            } else {
                // Sumar un día para que el evento ocupe todo el día
                const end = new Date(endDate);
                end.setDate(end.getDate() + 1);
                eventEnd = end.toISOString().split('T')[0];
            }

            return {
                id: String(task.id),  // ID como string
                title: task.name,
                start: eventStart,
                end: eventEnd,
                allDay: true,
                backgroundColor: statusColors[task.status] || '#95a5a6',
                borderColor: 'transparent',
                textColor: '#ffffff',
                classNames: [`status-${task.status}`, 'fc-event'],
                extendedProps: {
                    taskId: task.id,
                    taskName: task.name,
                    assignee: task.assignee || 'No asignado',
                    priority: task.priority || 'media',
                    progress: task.progress || 0,
                    estimatedTime: task.estimatedTime || 0,
                    timeLogged: task.timeLogged || 0,
                    description: task.description || '',
                    deadline: task.deadline,
                    status: task.status,
                    daysRemaining: daysRemaining,
                    isOverdue: isOverdue,
                    tooltipData: {
                        name: task.name,
                        taskId: task.id,
                        assignee: task.assignee || 'No asignado',
                        priority: task.priority || 'media',
                        progress: task.progress || 0,
                        estimatedTime: task.estimatedTime || 0,
                        timeLogged: task.timeLogged || 0,
                        description: task.description || '',
                        deadline: task.deadline,
                        status: task.status,
                        daysRemaining: daysRemaining,
                        isOverdue: isOverdue
                    }
                }
            };
        });

    console.log('✅ Tareas procesadas para calendario:', filteredTasks.length);
    return filteredTasks;
}


