/*************************
 * GESTIÓN DE PROYECTOS *
 *************************/
// ==================== CREAR NUEVO PROYECTO CORREGIDO ====================
function createNewProject() {
  // 👇 AÑADE ESTAS LÍNEAS AL INICIO 👇
  const savedProjects = JSON.parse(localStorage.getItem('projects') || '[]');
  if (localStorage.getItem('userPlan') === 'free' && savedProjects.length >= 1) {
    showNotification('💡 El plan Free permite solo 1 proyecto. Actualiza a Professional.');
    return;
  }
  // 👆 HASTA AQUÍ 👆

  const projectName = prompt('Ingrese el nombre del proyecto:');
  if (!projectName) return;

  const totalTime = prompt('Ingrese el tiempo total estimado del proyecto (horas):');
  const timeValue = totalTime ? parseFloat(totalTime) || 0 : 0;

  // ===== 🔥 NUEVO: Crear proyecto con estructura COMPLETA =====
  const newProject = {
    name: projectName,
    totalProjectTime: timeValue, // ← IMPORTANTE para estadísticas
    tasks: [],
    clienteId: localStorage.getItem('clienteId'), // ← Asignar clienteId actual
    createdAt: new Date().toISOString() // ← Para tracking
  };

  projects.push(newProject);

  // 🔑 seleccionar el proyecto recién creado
  currentProjectIndex = projects.length - 1;

  // 💾 persistir
  updateLocalStorage();


if (window.SlackNotifier) SlackNotifier.projectCreated(newProject);

  // === AGREGAR ESTA LÍNEA ===
  if (window.syncManager) window.syncManager.notifyChange('project-changed', { 
      action: 'created', 
      projectIndex: currentProjectIndex, 
      projectName: projectName 
  });
  
  renderProjects();
  selectProject(currentProjectIndex);
  actualizarAsignados();
  showNotification(`✅ Proyecto "${newProject.name}" creado`);
  
  // 🔥 Mensaje de ayuda
  console.log('💡 Recuerda: Para que las estadísticas funcionen, asigna tiempo estimado a las tareas');
}

// ============================================
// RENDERIZAR PROYECTOS CON FILTRO DE PERMISOS
// ============================================
function renderProjects() {
    const projectListContainer = document.getElementById('projectList');
    if (!projectListContainer) {
        console.log('⚠️ No se encontró projectListContainer');
        return;
    }
    
    // Obtener proyectos permitidos (AHORA SÍ FILTRA POR CLIENTEID)
    const proyectosPermitidos = getProyectosPermitidos();
    console.log('📋 Proyectos a renderizar:', proyectosPermitidos.length);
    
    projectListContainer.innerHTML = '';
    
    if (proyectosPermitidos.length === 0) {
        projectListContainer.innerHTML = `
            <li style="color: #95a5a6; text-align: center; padding: 20px; list-style: none;">
                <i class="fas fa-folder-open" style="font-size: 24px; margin-bottom: 10px; display: block;"></i>
                No tienes proyectos creados
            </li>
        `;
        return;
    }
    
    const user = JSON.parse(localStorage.getItem('user') || '{}');
    
    proyectosPermitidos.forEach((project) => {
        // Encontrar el índice REAL en el array original
        const realIndex = projects.findIndex(p => 
            p.name === project.name && 
            p.clienteId === project.clienteId
        );
        
        if (realIndex === -1) return;
        
        const li = document.createElement('li');
        li.className = 'project-item';
        li.dataset.projectIndex = realIndex;
        
        // Sistema legacy de permisos (opcional)
        const permiso = user.proyectosPermitidos?.find(p => p.proyectoIndex === realIndex);
        
        li.innerHTML = `
            <span>
                ${project.name}
                ${permiso ? `<span class="rol-badge" style="
                    font-size: 10px;
                    background: #8b5cf6;
                    color: white;
                    padding: 2px 8px;
                    border-radius: 10px;
                    margin-left: 10px;
                    display: inline-block;
                ">${permiso.rol}</span>` : ''}
            </span>
            <div class="project-menu" onclick="event.stopPropagation(); toggleProjectMenu(event, ${realIndex})">⋮</div>
            <div class="project-context-menu" id="project-menu-${realIndex}">
                <div class="project-context-menu-item edit" onclick="editProjectFromMenu(${realIndex})">Editar</div>
                <div class="project-context-menu-item delete" onclick="deleteProjectFromMenu(${realIndex})">Eliminar</div>
            </div>
        `;
        
        li.addEventListener('click', () => selectProject(realIndex));
        projectListContainer.appendChild(li);
    });
    
    console.log(`✅ Renderizados ${proyectosPermitidos.length} proyectos en el menú`);
    
    // Actualizar estilos del proyecto seleccionado
    setTimeout(updateProjectSelectionStyles, 100);
}

// Función auxiliar para estilos
function updateProjectSelectionStyles() {
    document.querySelectorAll('.project-item').forEach(item => {
        const idx = parseInt(item.dataset.projectIndex);
        if (idx === currentProjectIndex) {
            item.style.background = 'rgba(52, 152, 219, 0.2)';
            item.style.border = '1px solid #3498db';
        } else {
            item.style.background = 'rgba(255,255,255,0.05)';
            item.style.border = '1px solid rgba(255,255,255,0.1)';
        }
    });
}


function selectProject(index) {
  console.trace('🧭 selectProject llamado');

  // 🧠 Validar índice
  if (index < 0 || index >= projects.length) {
    console.warn(`⚠️ Índice de proyecto inválido (${index})`);
    return;
  }

  // 🔥 NUEVO: Verificar que el usuario tiene acceso a este proyecto
  const clienteId = localStorage.getItem('clienteId');
  const project = projects[index];
  
  if (!project) return;
  
  // Verificar acceso por clienteId
  if (project.clienteId && project.clienteId !== clienteId) {
    console.log('🔒 No tienes acceso a este proyecto');
    // Mostrar notificación si existe la función
    if (typeof showNotification === 'function') {
      showNotification('No tienes acceso a este proyecto', 'error');
    }
    return;
  }

  // Actualizar índice actual
  currentProjectIndex = index;

  // Guardar en localStorage el índice seleccionado
  localStorage.setItem('currentProjectIndex', index);

// 🔌 SOCKET → unir al proyecto usando el índice (currentProjectIndex)
if (window.tiempoRealSocket && currentProjectIndex !== undefined) {
    console.log("🔌 Uniéndose a la sala del proyecto índice:", currentProjectIndex);
    window.tiempoRealSocket.emit("join-project", currentProjectIndex);
}


  // 📝 Actualizar nombres del proyecto en todas las vistas
  const projectNameDisplay = document.getElementById('projectName');
  const projectNameList = document.getElementById('projectNameList');
  const projectNameCalendar = document.getElementById('projectNameCalendar');
  const projectNameGantt = document.getElementById('projectNameGantt');
  const projectNameReports = document.getElementById('projectNameReports');
  const projectNameDashboard = document.getElementById('projectNameDashboard');

  if (projectNameDisplay) projectNameDisplay.textContent = project.name;
  if (projectNameList) projectNameList.textContent = project.name;
  if (projectNameCalendar) projectNameCalendar.textContent = project.name;
  if (projectNameGantt) projectNameGantt.textContent = project.name;
  if (projectNameReports) projectNameReports.textContent = project.name;
  if (projectNameDashboard) projectNameDashboard.textContent = project.name;

  // ⏱️ Tiempo total del proyecto
  const totalTimeElement = document.getElementById('totalProjectTime');
  if (totalTimeElement) {
    totalTimeElement.textContent = `${project.totalProjectTime || 0} horas`;
  }

  // 🔄 Actualizaciones generales
  if (typeof actualizarAsignados === 'function') actualizarAsignados();
  if (typeof renderKanbanTasks === 'function') renderKanbanTasks();
  if (typeof updateTaskList === 'function') updateTaskList();
  if (typeof updateStatistics === 'function') updateStatistics();
  if (typeof updateProjectDatesFromTasks === 'function') updateProjectDatesFromTasks();
  if (typeof updateProjectProgress === 'function') updateProjectProgress();
 // if (typeof updateProjectStatusLabel === 'function') updateProjectStatusLabel();

  // 📊 Reportes
  if (typeof generateReports === 'function') generateReports();
  if (typeof generatePieChart === 'function' && typeof getStats === 'function') {
    generatePieChart(getStats());
  }

  // ⚠️ Riesgos, acciones e hitos
  setTimeout(() => {
    if (typeof loadRisksFromLocalStorage === 'function') loadRisksFromLocalStorage();
    if (typeof loadActionsFromLocalStorage === 'function') loadActionsFromLocalStorage();
    if (typeof loadMilestonesFromLocalStorage === 'function') loadMilestonesFromLocalStorage();
    if (typeof updateMilestonesStatus === 'function') updateMilestonesStatus();
  }, 50);

  // 🔁 Re-renderizar dashboard si está visible
  const dashboardView = document.getElementById('dashboardView');
  if (
    dashboardView &&
    getComputedStyle(dashboardView).display !== 'none'
  ) {
    console.log('🔁 Re-render dashboard por cambio de proyecto');
    setTimeout(() => {
      if (typeof renderDashboard === 'function') renderDashboard();
    }, 50);
  }

  // 🔀 Renderizar vista activa
  const activeView = getActiveView();
  switch (activeView) {
    case 'calendar':
      if (typeof renderCalendar === 'function') renderCalendar();
      break;
    case 'profitability':
      if (typeof renderProfitabilityView === 'function') renderProfitabilityView();
      break;
    case 'dashboard':
      // Ya se renderizó arriba
      break;
    default:
      // Para otras vistas, asegurar que se rendericen
      if (activeView === 'board' && typeof renderKanbanTasks === 'function') {
        renderKanbanTasks();
      } else if (activeView === 'list' && typeof renderListTasks === 'function') {
        renderListTasks();
      } else if (activeView === 'gantt' && typeof renderGanttChart === 'function') {
        renderGanttChart();
      }
  }
  
  // 🔥 NUEVO: Actualizar estilos del menú lateral
  setTimeout(() => {
    document.querySelectorAll('.project-item').forEach(item => {
      const idx = parseInt(item.dataset.projectIndex);
      if (idx === index) {
        item.style.background = 'rgba(52, 152, 219, 0.2)';
        item.style.border = '1px solid #3498db';
        // Asegurar que el checkmark se vea
        const checkmark = item.querySelector('div > div:last-child');
        if (checkmark) {
          checkmark.style.background = '#3498db';
          checkmark.style.color = 'white';
        }
      } else {
        item.style.background = 'rgba(255,255,255,0.05)';
        item.style.border = '1px solid rgba(255,255,255,0.1)';
        const checkmark = item.querySelector('div > div:last-child');
        if (checkmark) {
          checkmark.style.background = 'rgba(255,255,255,0.1)';
          checkmark.style.color = 'transparent';
        }
      }
    });
  }, 100);

  console.log(`✅ Proyecto seleccionado: "${project.name}"`);
}



function editProjectName(index) {
  const newName = prompt('Ingrese el nuevo nombre:', projects[index].name);
  if (newName && newName.trim()) {
    projects[index].name = newName.trim();
    updateLocalStorage();
    renderProjects();
    selectProject(index);
    showNotification(`Nombre del proyecto actualizado a "${newName}"`);
  }
}

function deleteProject(index) {
  // 🔹 Intentar corregir índices inválidos antes de continuar
  if (index < 0 || index >= projects.length) {
    console.warn("⚠️ Índice de proyecto inválido:", index);

    // Buscar el proyecto activo por nombre o ID
    const currentProject = projects.find(p =>
      p.id === currentProjectId ||
      (typeof currentProject !== "undefined" && p.name === currentProject.name)
    );

    // Si lo encuentra, recalcula el índice
    if (currentProject) {
      index = projects.indexOf(currentProject);
      console.log(`✅ Índice corregido automáticamente a: ${index}`);
    } else {
      showNotification("⚠️ No se encontró el proyecto a eliminar");
      return;
    }
  }

  const project = projects[index];
  if (!project) {
    console.warn(`❌ Proyecto no encontrado en índice ${index}`);
    return;
  }

  const confirmDelete = confirm(`¿Eliminar el proyecto "${project.name}"?`);
  if (!confirmDelete) return;

  // 🔹 Generar una clave única (según ID o índice)
  const projectKey = project.id ? `project_${project.id}` : `project_${index}`;

  // 1️⃣ Eliminar en Firebase
  if (window.firebaseManager?.isConnected) {
    window.firebaseManager.db.ref(`projects/${projectKey}`).remove()
      .then(() => console.log(`✅ Proyecto eliminado en Firebase: ${projectKey}`))
      .catch(err => console.error('❌ Error al eliminar en Firebase:', err));
  }

  // 2️⃣ Eliminar datos relacionados del localStorage
  try {
    const riskKey = `projectRisks_${index}_${project.name.replace(/\s+/g, '_')}`;
    const actionKey = `projectActions_${index}`;
    const milestoneKey = `projectMilestones_${index}`;
    localStorage.removeItem(riskKey);
    localStorage.removeItem(actionKey);
    localStorage.removeItem(milestoneKey);
  } catch (e) {
    console.warn("⚠️ Error eliminando datos relacionados:", e);
  }

  // 3️⃣ Eliminar del arreglo local
  projects.splice(index, 1);
  updateLocalStorage();

  // 4️⃣ Reajustar selección actual
  if (projects.length === 0) {
    createNewProject();
  } else {
    currentProjectIndex = Math.max(0, Math.min(index, projects.length - 1));
    renderProjects();
    selectProject(currentProjectIndex);
  }

  showNotification(`🗑️ Proyecto "${project.name}" eliminado correctamente`);
  console.log(`🗑️ Proyecto eliminado: ${project.name}`);
}

/*********************
 * GESTIÓN DE TAREAS *
 *********************/
function createNewTask(e) {
    if (e) e.preventDefault();

    console.log('🔄 Iniciando creación de tarea...');

    // 🔒 Validación robusta del proyecto actual
    if (!projects || !Array.isArray(projects)) {
        console.error('❌ Error: projects no está inicializado');
        showNotification('Error: No se pueden crear tareas en este momento');
        return false;
    }

    if (typeof currentProjectIndex === 'undefined' || currentProjectIndex === null) {
        console.error('❌ Error: currentProjectIndex no definido');
        showNotification('Error: No hay proyecto seleccionado');
        return false;
    }

    const currentProject = projects[currentProjectIndex];
    if (!currentProject) {
        console.error('❌ Error: Proyecto actual no existe en índice', currentProjectIndex);
        showNotification('Error: Proyecto no válido');
        return false;
    }

    // Asegurar que el proyecto tenga array de tasks
    if (!currentProject.tasks || !Array.isArray(currentProject.tasks)) {
        console.log('🔄 Inicializando tasks array...');
        currentProject.tasks = [];
    }

    // OBTENER VALORES
    const taskNameInput = document.getElementById('taskName');
    const taskName = taskNameInput ? taskNameInput.value.trim() : '';
    
    console.log('📝 Nombre de tarea:', taskName);

    if (!taskName) {
        showNotification('❌ El nombre de la tarea es requerido');
        if (taskNameInput) taskNameInput.focus();
        return false;
    }

    // MANEJO COMPLETO DE ARCHIVOS
    let taskFile = null;
    const fileInput = document.getElementById('fileUpload');
    
    if (fileInput && fileInput.files.length > 0) {
        const file = fileInput.files[0];
        
        const maxSize = 5 * 1024 * 1024; // 5MB
        if (file.size > maxSize) {
            showNotification('❌ El archivo es demasiado grande (máximo 5MB)');
            return false;
        }

        taskFile = {
            name: file.name,
            size: file.size,
            type: file.type,
            lastModified: file.lastModified,
            uploadDate: new Date().toISOString()
        };
        
        console.log('✅ Metadatos de archivo capturados:', taskFile);
        
        try {
            const fileKey = `task_file_${Date.now()}_${file.name.replace(/[^a-zA-Z0-9.]/g, '_')}`;
            taskFile.key = fileKey;
            
            const reader = new FileReader();
            
            reader.onload = function(e) {
                const fileData = {
                    data: e.target.result,
                    info: taskFile
                };
                localStorage.setItem(fileKey, JSON.stringify(fileData));
                console.log('💾 Archivo guardado en localStorage:', fileKey);
            };
            
            reader.onerror = function(error) {
                console.error('❌ Error guardando archivo:', error);
            };
            
            reader.readAsDataURL(file);
            
        } catch (error) {
            console.error('❌ Error en proceso de guardado:', error);
        }
        
    } else {
        console.log('📭 No se encontró archivo adjunto');
    }

    const storyPoints = Number(
        document.getElementById('estimatedHours')?.value || 0
    );

    console.log('📌 STORY POINTS (number) →', storyPoints, typeof storyPoints);

    const task = {
        id: Date.now(),
        name: taskName,
        startDate: document.getElementById('taskStartDate')?.value || new Date().toISOString().split('T')[0],
        deadline: document.getElementById('taskDeadline')?.value || new Date(Date.now() + 7*24*60*60*1000).toISOString().split('T')[0],
        priority: document.getElementById('taskPriority')?.value || 'baja',
        assignee: document.getElementById('taskAssignee')?.value || '',
        description: document.getElementById('taskDescription')?.value || '',
        status: 'pending',
        progress: 0,
        estimatedTime: storyPoints,
        timeLogged: 0,
        timeHistory: [],
        subtasks: [],
        dependencies: [],
        file: taskFile
    };

    console.log('✅ Tarea creada:', task);
    console.group('🧪 STORY POINTS CHECK');
    console.log('storyPoints →', task.storyPoints);
    console.log('tipo →', typeof task.storyPoints);
    console.groupEnd();

    // AGREGAR TAREA AL PROYECTO
    try {
        currentProject.tasks.push(task);
        console.log('✅ Tarea agregada al proyecto:', task.name);
        
        updateLocalStorage();
if (window.SlackNotifier) SlackNotifier.taskCreated(task, projects[currentProjectIndex].name);
             
        
        // 🔥 NOTIFICAR A OTROS USUARIOS
        if (tiempoRealSocket && tiempoRealSocket.connected) {
            tiempoRealSocket.emit('task-created', {
    projectId: currentProjectIndex,
    task: task
});
        }

        actualizarAsignados();
        aplicarFiltros();
        generatePieChart(getStats());
        updateProjectProgress();
        renderKanbanTasks();

        // ========== 🆕 NUEVO: DISPARAR EVENTOS PARA EFECTOS VISUALES ==========
        document.dispatchEvent(new Event('taskCreated'));
        document.dispatchEvent(new Event('tasksRendered'));
        
        // Actualizar contadores con animación
        setTimeout(() => {
            if (typeof actualizarContadoresColumnas === 'function') {
                actualizarContadoresColumnas();
            }
        }, 100);
        // ========== FIN NUEVO ==========

        // Cerrar modal y limpiar formulario
        const createTaskModal = document.getElementById('createTaskModal');
        if (createTaskModal) {
            createTaskModal.style.display = 'none';
        }
        const form = document.getElementById('createTaskForm');
        if (form) form.reset();
        showNotification(`✅ Tarea "${task.name}" creada${task.file ? ' con archivo adjunto' : ''}`);

        // ✅ ACTUALIZAR EL BURNDOWN CHART
        refreshBurndown();
        
        // ✅ ACTUALIZAR CALENDARIO AUTOMÁTICAMENTE (NUEVO)
        setTimeout(() => {
            forceRefreshCalendar();
        }, 100);
        
        // ✅ ACTUALIZAR VISTA DE LISTA SI ESTÁ ACTIVA
        const listView = document.getElementById('listView');
        if (listView && listView.classList.contains('active') && typeof renderListTasks === 'function') {
            setTimeout(() => {
                renderListTasks();
            }, 100);
        }
        
        // ✅ ACTUALIZAR DASHBOARD SI ESTÁ ACTIVO
        const dashboardView = document.getElementById('dashboardView');
        if (dashboardView && dashboardView.classList.contains('active') && typeof renderDashboard === 'function') {
            setTimeout(() => {
                renderDashboard();
            }, 100);
        }
        
        return true;
        
    } catch (error) {
        console.error('❌ Error al guardar tarea:', error);
        showNotification('❌ Error al crear la tarea');
        return false;
    }
}


function deleteTask(taskStr) {
    const task = JSON.parse(decodeURIComponent(taskStr));
    if (confirm(`¿Estás seguro de eliminar "${task.name}"? Esta acción no se puede deshacer.`)) {
        
        // Notificaciones
        const project = projects[currentProjectIndex];
        if (window.SlackNotifier) {
            window.SlackNotifier.taskDeleted(task.name, project.name);
        }
        
        if (tiempoRealSocket && tiempoRealSocket.connected) {
            tiempoRealSocket.emit('task-changed', {
                projectId: currentProjectIndex,
                taskId: task.id,
                taskName: task.name,
                userName: 'Usuario actual',
                type: 'task-deleted',
                timestamp: new Date().toISOString()
            });
        }
        
        // Eliminar tarea
        projects[currentProjectIndex].tasks = projects[currentProjectIndex].tasks.filter(t => t.id !== task.id);
        updateLocalStorage();
        if (window.SlackNotifier) SlackNotifier.taskDeleted(task.name, projects[currentProjectIndex].name);


        // Actualizar vistas
        actualizarAsignados();
        aplicarFiltros();
        generatePieChart(getStats());
        updateProjectProgress();
        showNotification(`Tarea "${task.name}" eliminada`);
        
        // Disparar eventos
        document.dispatchEvent(new Event('taskDeleted'));
        document.dispatchEvent(new Event('tasksRendered'));
        
        // Actualizar todas las vistas después de un breve delay
        setTimeout(() => {
            if (typeof actualizarContadoresColumnas === 'function') actualizarContadoresColumnas();
            if (typeof refreshBurndown === 'function') refreshBurndown();
            if (typeof forceRefreshCalendar === 'function') forceRefreshCalendar();
            
            // Actualizar vista activa
            const activeView = getActiveView();
            if (activeView === 'list' && typeof renderListTasks === 'function') renderListTasks();
            if (activeView === 'board' && typeof renderKanbanTasks === 'function') renderKanbanTasks();
            if (activeView === 'dashboard' && typeof renderDashboard === 'function') renderDashboard();
            if (activeView === 'reports' && typeof generateReports === 'function') generateReports();
            if (activeView === 'timeAllocation' && typeof loadTimeAllocationData === 'function') loadTimeAllocationData();
        }, 100);
    }
}
/*********************
 * FUNCIÓN DE ESTIMACIÓN CON IA *
 *********************/
function setupAIEstimation() {
    console.log('🔄 Configurando IA...');
    
    const aiButton = document.getElementById('estimateWithAI');
    const resultElement = document.getElementById('aiEstimationResult');
    
    if (!aiButton || !resultElement) {
        console.log('❌ Elementos no encontrados');
        return;
    }
    
    // Clonar y reemplazar el botón para eliminar listeners antiguos
    const newButton = aiButton.cloneNode(true);
    aiButton.parentNode.replaceChild(newButton, aiButton);
    
    // Agregar listener al NUEVO botón
    newButton.addEventListener('click', function() {
        console.log('🎯 Botón de IA clickeado - Iniciando análisis...');
        
        const taskName = document.getElementById('taskName')?.value.trim();
        const taskDescription = document.getElementById('taskDescription')?.value.trim();
        const priority = document.getElementById('taskPriority')?.value;
        
        if (!taskName) {
            alert('❌ Primero escribe el nombre de la tarea');
            return;
        }
        
        // Guardar estado original
        const originalText = this.innerHTML;
        const originalBackground = this.style.background;
        
        // Cambiar a estado de carga
        this.innerHTML = '⏳ Analizando...';
        this.style.background = '#3498db';
        this.disabled = true;
        
        // Limpiar resultado anterior
        resultElement.style.display = 'none';
        resultElement.innerHTML = '';
        
        setTimeout(() => {
            try {
                // Análisis mejorado
                const text = (taskName + ' ' + (taskDescription || '')).toLowerCase();
                console.log('🔍 Analizando texto:', text);
                
                let hours = 4;
                let complexity = 2;
                let reasoning = "Tarea estándar";

                // ✅ ANÁLISIS MEJORADO - DETECCIÓN DE COMPLEJIDAD
                // PALABRAS CLAVE POR COMPLEJIDAD
                const complexityKeywords = {
                    1: ['revisar', 'corregir', 'actualizar', 'enviar', 'verificar', 'chequear', 'limpiar', 'organizar', 'comprobar'],
                    2: ['configurar', 'crear', 'migrar', 'cargar', 'exportar', 'importar', 'backup', 'restaurar', 'instalar', 'preparar'],
                    3: ['desarrollar', 'implementar', 'integrar', 'optimizar', 'automatizar', 'procesar', 'analizar', 'probar', 'validar'],
                    4: ['diseñar', 'arquitectura', 'sistema', 'plataforma', 'api rest', 'base de datos', 'seguridad', 'escalar', 'monitorizar'],
                    5: ['microservicios', 'machine learning', 'inteligencia artificial', 'blockchain', 'iot', 'big data', 'transformación', 'estrategia']
                };

                // DETECTAR COMPLEJIDAD BASADA EN PALABRAS CLAVE
                let detectedComplexity = 2; // Por defecto

                for (let [level, keywords] of Object.entries(complexityKeywords)) {
                    if (keywords.some(keyword => text.includes(keyword))) {
                        detectedComplexity = Math.max(detectedComplexity, parseInt(level));
                    }
                }

                // AJUSTAR HORAS SEGÚN COMPLEJIDAD DETECTADA
                switch(detectedComplexity) {
                    case 1:
                        hours = 2;
                        reasoning = "Tarea muy simple - Revisión/Corrección";
                        break;
                    case 2:
                        hours = 4;
                        reasoning = "Tarea simple - Configuración/Creación básica";
                        break;
                    case 3:
                        hours = 6;
                        reasoning = "Tarea media - Desarrollo/Implementación";
                        break;
                    case 4:
                        hours = 10;
                        reasoning = "Tarea compleja - Diseño/Arquitectura";
                        break;
                    case 5:
                        hours = 16;
                        reasoning = "Tarea muy compleja - Sistema avanzado";
                        break;
                }

                // ✅ DETECCIÓN ESPECÍFICA POR TIPO DE TAREA
                if (text.includes('api') && text.includes('base de datos') && text.includes('integracion')) {
                    hours = 20;
                    complexity = 5;
                    reasoning = "🚀 INTEGRACIÓN COMPLEJA: Múltiples sistemas conectados";
                } 
                else if (text.includes('api rest') || text.includes('rest api')) {
                    hours = 12;
                    complexity = 4;
                    reasoning = "🌐 API REST: Desarrollo completo con endpoints";
                }
                else if (text.includes('microservicios')) {
                    hours = 24;
                    complexity = 5;
                    reasoning = "🔗 ARQUITECTURA: Microservicios distribuidos";
                }
                else if (text.includes('api')) {
                    hours = 8;
                    complexity = 3;
                    reasoning = "⚙️ API: Desarrollo de interfaz básica";
                }
                else if (text.includes('base de datos') && (text.includes('diseñar') || text.includes('arquitectura'))) {
                    hours = 14;
                    complexity = 4;
                    reasoning = "🗃️ DISEÑO BD: Arquitectura de base de datos";
                }
                else if (text.includes('base de datos') && text.includes('optimizacion')) {
                    hours = 8;
                    complexity = 4;
                    reasoning = "📊 OPTIMIZACIÓN BD: Mejora de rendimiento";
                }
                else if (text.includes('base de datos')) {
                    hours = 6;
                    complexity = 3;
                    reasoning = "💾 BASE DE DATOS: Trabajo con datos";
                }
                else if (text.includes('configurar') && (text.includes('red') || text.includes('vlan') || text.includes('firewall'))) {
                    hours = 5;
                    complexity = 3;
                    reasoning = "🔧 CONFIGURACIÓN RED: Infraestructura de red";
                }
                else if (text.includes('configurar') && text.includes('servidor')) {
                    hours = 6;
                    complexity = 3;
                    reasoning = "🖥️ CONFIGURACIÓN: Servidor/Infraestructura";
                }
                else if (text.includes('configurar') && text.includes('equipo')) {
                    hours = 3;
                    complexity = 2;
                    reasoning = "📱 CONFIGURACIÓN: Equipos/Dispositivos";
                }
                else if (text.includes('desarrollo') && text.includes('completo')) {
                    hours = 15;
                    complexity = 4;
                    reasoning = "💻 DESARROLLO: Sistema completo desde cero";
                }
                else if (text.includes('desarrollo') || text.includes('implementar')) {
                    hours = 8;
                    complexity = 3;
                    reasoning = "💻 DESARROLLO: Módulo/funcionalidad";
                }
                else if (text.includes('revisar') || text.includes('corregir')) {
                    hours = 2;
                    complexity = 1;
                    reasoning = "📝 REVISIÓN: Análisis y correcciones";
                }
                else if (text.includes('diseñar') || text.includes('diseño') || text.includes('ui/ux')) {
                    hours = 6;
                    complexity = 3;
                    reasoning = "🎨 DISEÑO: Trabajo creativo/planificación";
                }
                else if (text.includes('documentación') || text.includes('documentar') || text.includes('manual')) {
                    hours = 3;
                    complexity = 2;
                    reasoning = "📚 DOCUMENTACIÓN: Creación/actualización";
                }
                else if (text.includes('testing') || text.includes('pruebas') || text.includes('qa')) {
                    hours = 4;
                    complexity = 2;
                    reasoning = "🧪 TESTING: Pruebas y control calidad";
                }
                else if (text.includes('machine learning') || text.includes('ia') || text.includes('inteligencia artificial')) {
                    hours = 20;
                    complexity = 5;
                    reasoning = "🤖 IA/ML: Modelo de inteligencia artificial";
                }
                else if (text.includes('mobile') || text.includes('app móvil') || text.includes('android') || text.includes('ios')) {
                    hours = 12;
                    complexity = 4;
                    reasoning = "📱 APP MÓVIL: Desarrollo aplicación móvil";
                }

                // ✅ AJUSTES POR CONTEXTO ESPECÍFICO
                if (text.includes('complej') || text.includes('complicad') || text.includes('difícil') || text.includes('avanzad') || text.includes('crític')) {
                    hours *= 1.4;
                    complexity = Math.min(5, complexity + 1);
                    reasoning += " | 🔴 COMPLEJO";
                }

                if (text.includes('simple') || text.includes('fácil') || text.includes('básico') || text.includes('rápido') || text.includes('sencillo')) {
                    hours *= 0.7;
                    complexity = Math.max(1, complexity - 1);
                    reasoning += " | 🟢 SIMPLE";
                }

                if (text.includes('urgent') || text.includes('crític') || text.includes('prioridad') || text.includes('inmediat')) {
                    hours *= 1.2;
                    reasoning += " | ⚡ URGENTE";
                }

                // ✅ AJUSTAR POR PRIORIDAD SELECCIONADA
                if (priority === 'alta') {
                    hours *= 1.3;
                    reasoning += " | 🔥 ALTA PRIORIDAD";
                } else if (priority === 'baja') {
                    hours *= 0.8;
                    reasoning += " | 🐢 BAJA PRIORIDAD";
                }

                // ✅ REDONDEAR Y LIMITAR
                hours = Math.max(0.5, Math.min(40, Math.round(hours * 2) / 2));
                complexity = Math.max(1, Math.min(5, complexity));
                
                console.log('📊 Estimación final:', { hours, complexity, reasoning });

                // Actualizar campo
                document.getElementById('estimatedHours').value = hours;
                
                // ✅ MOSTRAR RESULTADO DEBAJO DEL CAMPO
                resultElement.innerHTML = `
                    <div style="background: #d4edda; border: 1px solid #c3e6cb; border-radius: 4px; padding: 10px;">
                        <div style="font-weight: bold; color: #155724; margin-bottom: 5px;">
                            🧠 SUGERENCIA DE IA
                        </div>
                        <div style="color: #155724;">
                            <strong>${hours} horas</strong> | Complejidad: ${complexity}/5
                        </div>
                        <div style="color: #0c5460; font-size: 12px; margin-top: 4px;">
                            ${reasoning}
                        </div>
                        <div style="color: #6c757d; font-size: 11px; margin-top: 6px; border-top: 1px solid #b8daff; padding-top: 4px;">
                            💡 Basado en análisis de palabras clave y contexto
                        </div>
                    </div>
                `;
                resultElement.style.display = 'block';
                
                // ✅ Opcional: También mostrar notificación rápida
                if (typeof showNotification === 'function') {
                    showNotification(`✅ IA sugiere: ${hours} horas`);
                }
                
            } catch (error) {
                console.error('❌ Error en IA:', error);
                
                // ✅ Mostrar error en el mismo lugar
                resultElement.innerHTML = `
                    <div style="background: #f8d7da; border: 1px solid #f5c6cb; border-radius: 4px; padding: 10px; color: #721c24;">
                        ❌ Error en estimación IA. Usa tu criterio profesional.
                    </div>
                `;
                resultElement.style.display = 'block';
                
            } finally {
                // SIEMPRE restaurar el botón
                this.innerHTML = '🧠 Estimar con IA';
                this.style.background = originalBackground;
                this.disabled = false;
            }
        }, 800);
    });
    
    console.log('✅ IA configurada con detección mejorada de complejidades');
}





// ============================================
// 🛡️ INTERCEPTOR PERMANENTE DE DEPENDENCIAS
// ============================================
// Este código previene que currentDependencies se vacíe automáticamente
// cuando se cierra el dropdown de dependencias

console.log('🛡️ Cargando interceptor permanente de dependencias...');

// 1. INTERCEPTOR PARA PROTEGER currentDependencies
let _currentDependenciesBackup = [];
let _dependencyInterceptorActive = false;

function activateDependencyProtection() {
    if (_dependencyInterceptorActive) return;
    
    console.log('🔒 Activando protección de dependencias...');
    
    // Guardar el valor original si existe
    const originalValue = window.currentDependencies;
    
    // Crear getter/setter protegido
    Object.defineProperty(window, 'currentDependencies', {
        get() {
            return this._protectedDependencies || [];
        },
        set(newValue) {
            // Si se intenta vaciar y tenemos valores, preguntar
            if (Array.isArray(newValue) && newValue.length === 0 && 
                this._protectedDependencies && this._protectedDependencies.length > 0) {
                
                console.log('⚠️ Intento de vaciar dependencias bloqueado');
                console.log('   Dependencias actuales:', this._protectedDependencies);
                
                // NO permitir el vaciado - mantener valores actuales
                return;
            }
            
            // Guardar backup si hay valores
            if (newValue && newValue.length > 0) {
                _currentDependenciesBackup = [...newValue];
            }
            
            this._protectedDependencies = newValue;
            console.log('✅ currentDependencies actualizado:', newValue);
        },
        configurable: true,
        enumerable: true
    });
    
    // Inicializar con valor original si existe
    if (originalValue) {
        window.currentDependencies = originalValue;
    }
    
    _dependencyInterceptorActive = true;
    console.log('✅ Protección de dependencias activada');
}

// 2. PARCHE PARA updateSelectedDepsView (línea ~4269)
function patchUpdateSelectedDepsView() {
    console.log('🔧 Buscando updateSelectedDepsView para parchear...');
    
    // Esta función se ejecuta cuando se configuran dependencias
    // Necesitamos prevenir que vacíe currentDependencies
    
    // Buscar en el código la función problemática
    if (typeof updateSelectedDepsView === 'function') {
        const originalFunction = updateSelectedDepsView;
        
        updateSelectedDepsView = function() {
            console.log('🎯 updateSelectedDepsView interceptada');
            
            // Verificar si currentDependencies ya tiene valores
            if (window.currentDependencies && window.currentDependencies.length > 0) {
                console.log('✅ Preservando dependencias existentes:', window.currentDependencies);
                
                // NO ejecutar la función original que vacía
                // En su lugar, solo actualizar la vista si es necesario
                
                // Actualizar contador en la UI si existe
                const placeholder = document.querySelector('.deps-placeholder, [class*="deps"]');
                if (placeholder) {
                    const count = window.currentDependencies.length;
                    placeholder.textContent = `${count} dependencia(s) seleccionada(s)`;
                }
                
                return;
            }
            
            // Si no hay dependencias, ejecutar normal
            return originalFunction.apply(this, arguments);
        };
        
        console.log('✅ updateSelectedDepsView parcheada');
    } else {
        console.log('⚠️ updateSelectedDepsView no encontrada, creando parche preventivo');
        
        // Crear función dummy si no existe
        window.updateSelectedDepsView = function() {
            console.log('🛡️ updateSelectedDepsView (parche) - No vacía dependencias');
        };
    }
}

// 3. FUNCIÓN PARA CARGAR DEPENDENCIAS EXISTENTES AL ABRIR TAREA
function loadExistingDependenciesToDropdown() {
    // Esta función debe llamarse DESPUÉS de que se abra el modal de tarea
    // y se haya configurado el dropdown
    
    const select = document.querySelector('#dependency-styles, select[id*="dependency"]');
    if (!select) {
        console.log('⚠️ Dropdown no encontrado para cargar dependencias');
        return;
    }
    
    if (!window.currentDependencies || window.currentDependencies.length === 0) {
        console.log('ℹ️ No hay dependencias para cargar al dropdown');
        return;
    }
    
    console.log('📥 Cargando dependencias al dropdown:', window.currentDependencies);
    
    // Marcar opciones como seleccionadas
    Array.from(select.options || []).forEach(option => {
        if (window.currentDependencies.includes(option.value)) {
            option.selected = true;
            console.log(`   ✓ Marcada: ${option.text} (${option.value})`);
        }
    });
    
    // Forzar evento change para actualizar UI
    select.dispatchEvent(new Event('change', { bubbles: true }));
    
    console.log('✅ Dependencias cargadas al dropdown');
}

// 4. INTERCEPTAR showTaskDetails PARA CARGAR DEPENDENCIAS
function interceptShowTaskDetails() {
    if (typeof showTaskDetails !== 'function') {
        console.log('❌ showTaskDetails no encontrada');
        return;
    }
    
    const originalShowTaskDetails = showTaskDetails;
    
    showTaskDetails = function(task) {
        console.log('🎯 showTaskDetails interceptada para:', task.name);
        
        // Llamar función original
        const result = originalShowTaskDetails.apply(this, arguments);
        
        // Después de que se muestre el modal, cargar dependencias al dropdown
        setTimeout(() => {
            loadExistingDependenciesToDropdown();
        }, 500);
        
        return result;
    };
    
    console.log('✅ showTaskDetails interceptada correctamente');
}

// 5. INICIALIZAR TODO CUANDO SE CARGA LA PÁGINA
function initializeDependencySystem() {
    console.log('🚀 Inicializando sistema de dependencias permanente...');
    
    // Activar protección
    activateDependencyProtection();
    
    // Parchear función problemática
    setTimeout(patchUpdateSelectedDepsView, 1000);
    
    // Interceptar apertura de tareas
    setTimeout(interceptShowTaskDetails, 1500);
    
    // También monitorear cuando se abre el modal
    const modal = document.getElementById('taskDetails');
    if (modal) {
        const observer = new MutationObserver(function(mutations) {
            mutations.forEach(function(mutation) {
                if (mutation.type === 'attributes' && mutation.attributeName === 'style') {
                    if (modal.style.display !== 'none') {
                        console.log('🎯 Modal de tarea abierto - Configurando dependencias...');
                        
                        // Esperar a que cargue el dropdown
                        setTimeout(() => {
                            loadExistingDependenciesToDropdown();
                        }, 800);
                    }
                }
            });
        });
        
        observer.observe(modal, { attributes: true });
        console.log('✅ Observer configurado para modal');
    }
    
    console.log('✅ Sistema de dependencias inicializado permanentemente');
}

// 6. EJECUTAR INICIALIZACIÓN
// Ejecutar cuando el DOM esté listo
if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initializeDependencySystem);
} else {
    initializeDependencySystem();
}

// ============================================
// 🎮 COMANDOS DE DIAGNÓSTICO (opcional - para desarrollo)
// ============================================

window.debugDependencies = function() {
    console.log('🔍 DIAGNÓSTICO DE DEPENDENCIAS:');
    console.log('   - currentDependencies:', window.currentDependencies);
    console.log('   - Backup:', _currentDependenciesBackup);
    console.log('   - Interceptor activo:', _dependencyInterceptorActive);
    
    // Verificar localStorage
    try {
        const projectsJSON = localStorage.getItem('projects');
        if (projectsJSON) {
            const projects = JSON.parse(projectsJSON);
            
            // Buscar tarea actual
            const modal = document.getElementById('taskDetails');
            if (modal && modal.style.display !== 'none') {
                const inputs = modal.querySelectorAll('input');
                for (let input of inputs) {
                    if (input.value && /^\d{10,}$/.test(input.value)) {
                        const taskId = parseInt(input.value);
                        
                        for (let project of projects) {
                            if (project.tasks) {
                                const task = project.tasks.find(t => t.id === taskId);
                                if (task) {
                                    console.log(`   - Tarea "${task.name}" en localStorage:`);
                                    console.log(`     * Dependencias:`, task.dependencies || '[]');
                                    break;
                                }
                            }
                        }
                        break;
                    }
                }
            }
        }
    } catch (e) {
        console.log('   - Error leyendo localStorage:', e.message);
    }
};

console.log('🛡️ Interceptor permanente de dependencias cargado');





