// =============================================

function initializeMoveButtonsCompleteSolution() {
    console.log('🎯 INICIANDO SOLUCIÓN COMPLETA PARA MOVIMIENTO...');
    
    // Reemplazar completamente las funciones de movimiento
    window.moveTaskUp = function(taskId, status) {
        console.log(`⬆️ Moviendo tarea ${taskId} hacia arriba en ${status}...`);
        return moveTaskInArray(taskId, status, -1);
    };
    
    window.moveTaskDown = function(taskId, status) {
        console.log(`⬇️ Moviendo tarea ${taskId} hacia abajo en ${status}...`);
        return moveTaskInArray(taskId, status, 1);
    };
    
    console.log('✅ FUNCIONES DE MOVIMIENTO RECONSTRUIDAS');
}

function moveTaskInArray(taskId, status, direction) {
    try {
        const project = projects[currentProjectIndex];
        if (!project || !project.tasks) {
            console.log('❌ No hay proyecto o tareas');
            return false;
        }
        
        // Obtener índices de todas las tareas del mismo status
        const statusIndices = [];
        project.tasks.forEach((task, index) => {
            if (task.status === status) {
                statusIndices.push(index);
            }
        });
        
        // Encontrar la posición de la tarea en el array de índices
        const taskIndexInProject = project.tasks.findIndex(task => task.id == taskId);
        const currentPositionInStatus = statusIndices.indexOf(taskIndexInProject);
        
        if (currentPositionInStatus === -1) {
            console.log('❌ Tarea no encontrada en el status:', status);
            return false;
        }
        
        // Calcular nueva posición
        const newPositionInStatus = currentPositionInStatus + direction;
        
        // Verificar límites de manera más precisa
        if (direction === -1 && currentPositionInStatus === 0) {
            console.log('⚠️ No se puede mover arriba - ya está en la primera posición');
            return false;
        }
        
        if (direction === 1 && currentPositionInStatus === statusIndices.length - 1) {
            console.log('⚠️ No se puede mover abajo - ya está en la última posición');
            return false;
        }
        
        console.log(`📊 Moviendo de posición ${currentPositionInStatus} a ${newPositionInStatus} en status ${status}`);
        
        // Reordenar las tareas
        const success = reorderProjectTasksCorrected(project, statusIndices, currentPositionInStatus, newPositionInStatus);
        
        if (success) {
            // Guardar cambios usando la función correcta
            if (typeof saveProjects === 'function') {
                saveProjects();
            } else if (typeof saveData === 'function') {
                saveData();
            } else {
                console.log('⚠️ No se encontró función de guardado, pero los cambios están en memoria');
            }
            
            // Actualizar vista
            setTimeout(() => {
                if (typeof renderKanbanTasks === 'function') {
                    renderKanbanTasks();
                }
            }, 100);
            
            return true;
        }
        
        return false;
        
    } catch (error) {
        console.error('❌ Error en moveTaskInArray:', error);
        return false;
    }
}

function reorderProjectTasksCorrected(project, statusIndices, fromIndex, toIndex) {
    try {
        // Obtener los índices reales en el array project.tasks
        const fromRealIndex = statusIndices[fromIndex];
        const toRealIndex = statusIndices[toIndex];
        
        console.log(`🔄 Moviendo de índice real ${fromRealIndex} a ${toRealIndex}`);
        
        // Remover la tarea de su posición actual
        const [movedTask] = project.tasks.splice(fromRealIndex, 1);
        
        // Insertar en la nueva posición
        project.tasks.splice(toRealIndex, 0, movedTask);
        
        console.log('✅ Orden actualizado en proyecto');
        console.log('Nuevo orden:', project.tasks.filter(t => t.status === movedTask.status).map(t => t.name));
        
        return true;
        
    } catch (error) {
        console.error('❌ Error en reorderProjectTasksCorrected:', error);
        return false;
    }
}

// Función para diagnosticar el estado actual
function diagnoseMovement() {
    const project = projects[currentProjectIndex];
    console.log('🔍 DIAGNÓSTICO DE MOVIMIENTO:');
    
    ['pending', 'inProgress', 'completed', 'overdue'].forEach(status => {
        const tasks = project.tasks.filter(t => t.status === status);
        if (tasks.length > 0) {
            console.log(`📋 ${status} (${tasks.length} tareas):`, tasks.map((t, i) => `${i}: ${t.name}`));
        }
    });
}

