// 🔧 Protege selectProject para evitar índice inválido
(function guardSelectProject() {
  const original = window.selectProject;
  if (typeof original !== 'function') {
    console.warn('⚠️ selectProject no está definida todavía. Se parcheará cuando exista.');
    // intentaremos parchear más tarde cuando exista
    const timer = setInterval(() => {
      if (typeof window.selectProject === 'function') {
        clearInterval(timer);
        // re-invocamos el parche recursivamente
        guardSelectProject();
      }
    }, 200);
    return;
  }

  window.selectProject = function(projectIndex, ...rest) {
    try {
      const idx = parseInt(projectIndex);
      const projectsFromWindow = Array.isArray(window.projects) ? window.projects : null;
      const projectsFromStorage = JSON.parse(localStorage.getItem('projects') || '[]');
      const projects = projectsFromWindow || projectsFromStorage || [];
      if (isNaN(idx) || idx < 0 || idx >= projects.length) {
        console.warn('⚠️ selectProject: índice inválido, evitando cambio →', projectIndex);
        // Puedes forzar a 0 o al último válido si prefieres:
        // const safeIdx = Math.max(0, Math.min(projects.length - 1, idx || 0));
        // return original.call(this, safeIdx, ...rest);
        return;
      }
      return original.call(this, projectIndex, ...rest);
    } catch (err) {
      console.error('❌ Error en guardSelectProject:', err);
    }
  };

  console.log('🔒 selectProject parchada (protección de índice inválido)');

})();


function formatFileSize(bytes) {
    if (!bytes || bytes === 0) return '0 Bytes';
    
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
}


function loadFileFromStorage(fileKey) {
    try {
        const fileData = JSON.parse(localStorage.getItem(fileKey));
        if (!fileData) {
            console.error('❌ Archivo no encontrado:', fileKey);
            return null;
        }
        return fileData;
    } catch (error) {
        console.error('❌ Error cargando archivo:', error);
        return null;
    }
}





