// 4. Función auxiliar para notificaciones
function showNotification(message, type = 'info') {
  console.log(`📢 Notificación [${type}]: ${message}`);
  
  const colors = {
    success: '#10b981',
    error: '#ef4444',
    warning: '#f59e0b',
    info: '#3b82f6'
  };
  
  // Crear notificación
  const notification = document.createElement('div');
  notification.textContent = message;
  notification.style.cssText = `
    position: fixed;
    top: 20px;
    right: 20px;
    padding: 15px 25px;
    background: ${colors[type] || colors.info};
    color: white;
    border-radius: 8px;
    z-index: 999999;
    box-shadow: 0 5px 15px rgba(0,0,0,0.2);
    animation: slideIn 0.3s ease;
  `;
  
  // Agregar animación CSS si no existe
  if (!document.querySelector('#notification-styles')) {
    const style = document.createElement('style');
    style.id = 'notification-styles';
    style.textContent = `
      @keyframes slideIn {
        from { transform: translateX(100%); opacity: 0; }
        to { transform: translateX(0); opacity: 1; }
      }
      @keyframes fadeOut {
        from { opacity: 1; }
        to { opacity: 0; }
      }
    `;
    document.head.appendChild(style);
  }
  
  document.body.appendChild(notification);
  
  // Auto-eliminar después de 5 segundos
  setTimeout(() => {
    notification.style.animation = 'fadeOut 0.3s ease';
    setTimeout(() => notification.remove(), 300);
  }, 5000);
}

// 5. Función para actualizar visualización de dependencias
function updateDependencyVisualization(sourceId, targetId, type) {
  console.log(`🎨 Actualizando visualización: ${sourceId} → ${targetId}`);
  
  // Encontrar elementos de las tareas
  const sourceElement = document.querySelector(`[data-task-id="${sourceId}"]`);
  const targetElement = document.querySelector(`[data-task-id="${targetId}"]`);
  
  if (sourceElement && targetElement) {
    // Agregar clases para estilización
    sourceElement.classList.add('has-dependency');
    targetElement.classList.add('has-dependency');
    
    // Crear línea visual (ejemplo simple)
    const container = sourceElement.closest('.tasks-container') || document.body;
    const line = document.createElement('div');
    line.className = 'dependency-line';
    line.dataset.source = sourceId;
    line.dataset.target = targetId;
    line.dataset.type = type;
    
    // Posicionar la línea (esto es un ejemplo básico)
    const sourceRect = sourceElement.getBoundingClientRect();
    const targetRect = targetElement.getBoundingClientRect();
    
    line.style.cssText = `
      position: absolute;
      top: ${sourceRect.top + sourceRect.height/2}px;
      left: ${sourceRect.right}px;
      width: ${targetRect.left - sourceRect.right}px;
      height: 2px;
      background: #3498db;
      z-index: 1000;
      pointer-events: none;
    `;
    
    container.appendChild(line);
    
    console.log('✅ Visualización de dependencia actualizada');
  }
}


