window.closeTeamMembersModal = function() {
  console.log('🔒 Cerrando modal de miembros del equipo...');
  
  // Método 1: Buscar y eliminar overlay por ID
  const overlay = document.getElementById('teamOverlay');
  if (overlay) {
    overlay.remove();
    console.log('✅ Overlay eliminado por ID');
    return;
  }
  
  // Método 2: Buscar overlay por estilo
  const overlays = document.querySelectorAll('div[style*="position: fixed"]');
  overlays.forEach(div => {
    const style = div.getAttribute('style') || '';
    if (style.includes('rgba(0,0,0,0.85)') || style.includes('background: rgba(0,0,0,0.85)')) {
      div.remove();
      console.log('✅ Overlay eliminado por estilo');
    }
  });
  
  // Método 3: Buscar por contenido específico
  document.querySelectorAll('div').forEach(div => {
    if (div.innerHTML && div.innerHTML.includes('Distribución Completa del Equipo')) {
      // Buscar el overlay padre
      let parent = div;
      while (parent) {
        const parentStyle = parent.getAttribute('style') || '';
        if (parentStyle.includes('position: fixed') && parentStyle.includes('background:')) {
          parent.remove();
          console.log('✅ Overlay eliminado por contenido');
          break;
        }
        parent = parent.parentElement;
      }
    }
  });
  
  // Método 4: Eliminar todos los overlays de equipo
  document.querySelectorAll('.team-members-overlay').forEach(el => el.remove());
};

















