// ========== FUNCIÓN DE NOTIFICACIÓN 100% INDEPENDIENTE ==========
function notificacionFiltro(message) {
  console.log(`📢 ${message}`);
  
  // Crear notificación completamente independiente
  const notification = document.createElement('div');
  notification.className = 'filtro-notificacion-' + Date.now();
  notification.textContent = message;
  notification.style.cssText = `
    position: fixed;
    top: 20px;
    right: 20px;
    background: #2ecc71;
    color: white;
    padding: 12px 20px;
    border-radius: 8px;
    z-index: 1000000;
    box-shadow: 0 5px 15px rgba(0,0,0,0.3);
    font-size: 14px;
    font-weight: 500;
    animation: filtroNotifIn 0.3s ease;
    max-width: 300px;
    word-break: break-word;
  `;
  
  // Agregar estilos de animación solo para nuestras notificaciones
  if (!document.getElementById('filtro-notif-styles')) {
    const style = document.createElement('style');
    style.id = 'filtro-notif-styles';
    style.textContent = `
      @keyframes filtroNotifIn {
        from {
          transform: translateX(100%);
          opacity: 0;
        }
        to {
          transform: translateX(0);
          opacity: 1;
        }
      }
      @keyframes filtroNotifOut {
        from {
          transform: translateX(0);
          opacity: 1;
        }
        to {
          transform: translateX(100%);
          opacity: 0;
        }
      }
    `;
    document.head.appendChild(style);
  }
  
  document.body.appendChild(notification);
  
  // Remover después de 3 segundos
  setTimeout(() => {
    notification.style.animation = 'filtroNotifOut 0.3s ease';
    setTimeout(() => notification.remove(), 300);
  }, 3000);
}

