// 1. Filtrar tareas críticas
window.filterCriticalTasksPremium = function() {
  console.log('🔴 Filtrando tareas críticas...');
  
  const ganttContainer = document.getElementById('premiumExecutiveGantt');
  if (!ganttContainer) {
    notificacionFiltro('❌ No hay Gantt Ejecutivo abierto');
    return;
  }
  
  const tasks = JSON.parse(ganttContainer.dataset.tasks || '[]');
  console.log('📋 Total tareas:', tasks.length);
  
  const criticalTasks = tasks.filter(t => t.critical);
  console.log('🔥 Tareas críticas encontradas:', criticalTasks.length);
  
  // Ocultar todas las tareas primero
  document.querySelectorAll('.premium-task').forEach(task => {
    task.style.display = 'none';
  });
  
  // Mostrar solo tareas críticas
  criticalTasks.forEach(task => {
    const taskElement = document.querySelector(`.premium-task[data-task-id="${task.id}"]`);
    if (taskElement) {
      taskElement.style.display = 'flex';
      taskElement.style.background = 'rgba(231, 76, 60, 0.2)';
      taskElement.style.border = '2px solid #e74c3c';
    }
  });
  
  notificacionFiltro(`✅ Mostrando ${criticalTasks.length} tareas críticas`);
};

// 2. Filtrar tareas atrasadas - VERSIÓN MEJORADA
window.filterDelayedTasksPremium = function() {
  console.log('⚡ Filtrando tareas atrasadas...');
  
  const ganttContainer = document.getElementById('premiumExecutiveGantt');
  if (!ganttContainer) {
    notificacionFiltro('❌ No hay Gantt Ejecutivo abierto');
    return;
  }
  
  const tasks = JSON.parse(ganttContainer.dataset.tasks || '[]');
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  
  // Tareas atrasadas según múltiples criterios
  const delayedTasks = tasks.filter(t => {
    // CRITERIO 1: Estado 'overdue' o 'rezagada' o similar
    const esEstadoAtrasado = 
      t.status === 'overdue' || 
      t.status === 'rezagada' || 
      t.status === 'rezagado' ||
      t.status === 'atrasada' ||
      t.status === 'atrasado' ||
      (t.status && t.status.toLowerCase().includes('rezag')) ||
      (t.status && t.status.toLowerCase().includes('atras'));
    
    if (esEstadoAtrasado) {
      console.log(`✅ "${t.name}" detectada por estado: ${t.status}`);
      return true;
    }
    
    // CRITERIO 2: Tareas pendientes o en progreso que ya deberían haber empezado
    if (t.startDay !== undefined) {
      const taskStart = new Date();
      taskStart.setDate(today.getDate() + (t.startDay || 0));
      taskStart.setHours(0, 0, 0, 0);
      
      const deberiaHaberEmpezado = 
        (t.status === 'pending' || t.status === 'inProgress') &&
        taskStart < today;
      
      if (deberiaHaberEmpezado) {
        console.log(`✅ "${t.name}" detectada por fecha de inicio`);
        return true;
      }
    }
    
    // CRITERIO 3: Tareas con deadline pasado
    if (t.deadline) {
      try {
        const deadlineDate = new Date(t.deadline);
        deadlineDate.setHours(0, 0, 0, 0);
        
        const deadlinePasado = 
          (t.status === 'pending' || t.status === 'inProgress') &&
          deadlineDate < today;
        
        if (deadlinePasado) {
          console.log(`✅ "${t.name}" detectada por deadline pasado`);
          return true;
        }
      } catch (e) {
        console.log(`⚠️ Error parseando deadline de "${t.name}":`, e.message);
      }
    }
    
    return false;
  });
  
  console.log('⏰ Tareas atrasadas encontradas:', delayedTasks.length);
  
  // Ocultar todas las tareas primero
  document.querySelectorAll('.premium-task').forEach(task => {
    task.style.display = 'none';
  });
  
  // Mostrar solo tareas atrasadas
  delayedTasks.forEach(task => {
    const taskElement = document.querySelector(`.premium-task[data-task-id="${task.id}"]`);
    if (taskElement) {
      taskElement.style.display = 'flex';
      taskElement.style.background = 'rgba(243, 156, 18, 0.2)';
      taskElement.style.border = '2px solid #f39c12';
      
      // Agregar indicador visual extra
      const existingBadge = taskElement.querySelector('.atrasada-badge');
      if (!existingBadge) {
        const badge = document.createElement('span');
        badge.className = 'atrasada-badge';
        badge.textContent = '⚠️ ATRASADA';
        badge.style.cssText = `
          position: absolute;
          top: 5px;
          right: 60px;
          background: #e74c3c;
          color: white;
          padding: 2px 8px;
          border-radius: 10px;
          font-size: 10px;
          font-weight: bold;
          z-index: 10;
        `;
        taskElement.style.position = 'relative';
        taskElement.appendChild(badge);
      }
    }
  });
  
  const mensaje = delayedTasks.length === 0 
    ? '✅ No hay tareas atrasadas' 
    : `⚠️ Mostrando ${delayedTasks.length} tarea(s) atrasada(s)`;
  
  notificacionFiltro(mensaje);
};

// 3. Filtrar por equipo
