// ========== FUNCIÓN PARA GUARDAR DEPENDENCIAS - VERSIÓN CORREGIDA ==========
window.saveDependencies = function(projectIndex) {
  console.log('💾 GUARDANDO DEPENDENCIAS...');
  console.log('Project index:', projectIndex);
  
  const modal = document.querySelector('.dependency-modal');
  if (!modal) {
    console.error('❌ No hay modal abierto');
    return;
  }
  
  if (projectIndex >= projects.length || projectIndex < 0) {
    alert('Error: Proyecto no válido.');
    return;
  }
  
  const currentProject = projects[projectIndex];
  const currentTasks = currentProject.tasks || [];
  
  console.log(`📊 Proyecto: ${currentProject.name}`);
  console.log(`📋 Tareas totales: ${currentTasks.length}`);
  
  // 1. LIMPIAR TODAS LAS DEPENDENCIAS EXISTENTES
  console.log('🧹 Limpiando dependencias existentes...');
  currentTasks.forEach(task => {
    if (task.dependencies && task.dependencies.length > 0) {
      console.log(`  Limpiando ${task.dependencies.length} dependencias de "${task.name}"`);
      task.dependencies = [];
    }
  });
  
  // 2. OBTENER NUEVAS DEPENDENCIAS DEL MODAL
  const dependenciesList = document.getElementById('dependenciesList');
  const newDependencies = [];
  
  if (dependenciesList) {
    dependenciesList.querySelectorAll('.dependency-item').forEach(item => {
      const fromId = item.dataset.fromId;
      const toId = item.dataset.toId;
      
      if (fromId && toId) {
        newDependencies.push({ fromId, toId });
        console.log(`📝 Nueva dependencia: ${fromId} -> ${toId}`);
      }
    });
  }
  
  console.log(`📦 Total de nuevas dependencias: ${newDependencies.length}`);
  
  // 3. APLICAR NUEVAS DEPENDENCIAS
  if (newDependencies.length > 0) {
    newDependencies.forEach(dep => {
      const fromId = dep.fromId.toString();
      const toId = dep.toId.toString();
      
      // Buscar la tara DESTINO (la que depende de la otra)
      const toTask = currentTasks.find(t => t.id && t.id.toString() === toId);
      
      if (toTask) {
        // Inicializar array si no existe
        if (!Array.isArray(toTask.dependencies)) {
          toTask.dependencies = [];
        }
        
        // Evitar duplicados
        if (!toTask.dependencies.includes(fromId)) {
          toTask.dependencies.push(fromId);
          console.log(`✅ Añadida dependencia a "${toTask.name}": depende de ${fromId}`);
        }
      } else {
        console.warn(`⚠️ No se encontró tarea destino con ID: ${toId}`);
      }
    });
  }
  
  // 4. MOSTRAR RESULTADO FINAL
  console.log('=== DEPENDENCIAS FINALES ===');
  currentTasks.forEach(task => {
    if (task.dependencies && task.dependencies.length > 0) {
      console.log(`📌 "${task.name}" (ID: ${task.id}) depende de:`, task.dependencies);
    }
  });
  
  // 5. GUARDAR CAMBIOS
  safeSave().then((success) => {
    if (success !== false) {
      console.log('✅ Dependencias guardadas correctamente');
      
      // Cerrar modal
      closeDependencyCreator();
      
      // Actualizar vista Gantt
      setTimeout(() => {
        refreshGanttView();
      }, 300);
      
      showNotification(`✅ ${newDependencies.length} dependencias guardadas`);
      
    } else {
      console.error('❌ Error al guardar en safeSave');
      alert('Error al guardar los cambios');
    }
  }).catch(error => {
    console.error('💥 Error crítico en safeSave:', error);
    alert('Error crítico: ' + error.message);
  });
};



// ========== FUNCIÓN PARA LIMPIAR TODAS LAS DEPENDENCIAS ==========
window.clearAllDependencies = function() {
  console.log('🗑️ Limpiando todas las dependencias...');
  
  if (!confirm('¿Estás seguro de eliminar TODAS las dependencias de este proyecto?\n\nEsta acción no se puede deshacer.')) {
    console.log('❌ Operación cancelada por el usuario');
    return;
  }
  
  const ganttContainer = document.getElementById('premiumExecutiveGantt');
  if (!ganttContainer) {
    alert('❌ No hay Gantt activo');
    return;
  }
  
  const projectIndex = parseInt(ganttContainer.dataset.projectIndex) || currentProjectIndex;
  
  if (projectIndex >= projects.length || projectIndex < 0) {
    alert('Error: Proyecto no válido.');
    return;
  }
  
  const currentProject = projects[projectIndex];
  let dependenciasEliminadas = 0;
  
  // Eliminar dependencias de todas las tareas
  currentProject.tasks.forEach(task => {
    if (task.dependencies && task.dependencies.length > 0) {
      dependenciasEliminadas += task.dependencies.length;
      task.dependencies = [];
      console.log(`🗑️ Limpiadas dependencias de "${task.name}"`);
    }
  });
  
  if (dependenciasEliminadas > 0) {
    // Guardar cambios
    safeSave().then(() => {
      console.log(`✅ ${dependenciasEliminadas} dependencias eliminadas`);
      
      // Actualizar vista Gantt
      if (typeof refreshGanttView === 'function') {
        refreshGanttView();
      } else {
        // Recargar Gantt manualmente
        const ganttContainer = document.getElementById('premiumExecutiveGantt');
        if (ganttContainer) {
          ganttContainer.remove();
          setTimeout(() => createCompleteGanttForCurrentProject(), 300);
        }
      }
      
      showNotification(`✅ ${dependenciasEliminadas} dependencias eliminadas`);
      
    }).catch(error => {
      console.error('❌ Error al guardar:', error);
      alert('Error al eliminar dependencias');
    });
  } else {
    alert('⚠️ No hay dependencias para eliminar');
  }
};








