// ========== ANÁLISIS PREDICTIVO IA (PARA EL BOTÓN DEL MENÚ LATERAL) ==========
window.runAIAnalysisPremium = function() {
    console.log('🤖 Ejecutando análisis predictivo IA...');
    
    const ganttContainer = document.getElementById('premiumExecutiveGantt');
    if (!ganttContainer) {
        showNotification('⚠️ Primero abre el Gantt Ejecutivo', 'warning');
        return;
    }
    
    const projectIndex = parseInt(ganttContainer.dataset.projectIndex) || currentProjectIndex;
    const currentProject = projects[projectIndex];
    const tasks = currentProject.tasks || [];
    
    if (tasks.length === 0) {
        showNotification('📭 No hay tareas para analizar', 'warning');
        return;
    }
    
    // Calcular métricas del proyecto
    const totalTasks = tasks.length;
    const completedTasks = tasks.filter(t => t.status === 'completed').length;
    const inProgressTasks = tasks.filter(t => t.status === 'inProgress').length;
    const pendingTasks = tasks.filter(t => t.status === 'pending').length;
    const criticalTasks = tasks.filter(t => t.critical).length;
    
    // Calcular porcentajes
    const completionRate = totalTasks > 0 ? (completedTasks / totalTasks) * 100 : 0;
    const progressRate = totalTasks > 0 ? ((completedTasks + (inProgressTasks * 0.5)) / totalTasks) * 100 : 0;
    
    // Análisis de riesgos
    let riskLevel = 'BAJO';
    let riskColor = '#2ecc71';
    let riskReasons = [];
    
    if (criticalTasks > totalTasks * 0.3) {
        riskLevel = 'ALTO';
        riskColor = '#e74c3c';
        riskReasons.push(`🔴 ${criticalTasks} tareas críticas (${Math.round((criticalTasks/totalTasks)*100)}%)`);
    }
    
    if (pendingTasks > totalTasks * 0.5) {
        riskLevel = riskLevel === 'BAJO' ? 'MEDIO' : riskLevel;
        riskColor = riskLevel === 'MEDIO' ? '#f39c12' : riskColor;
        riskReasons.push(`🟡 ${pendingTasks} tareas pendientes (${Math.round((pendingTasks/totalTasks)*100)}%)`);
    }
    
    if (completionRate < 30) {
        riskLevel = riskLevel === 'BAJO' ? 'MEDIO' : riskLevel;
        riskColor = riskLevel === 'MEDIO' ? '#f39c12' : riskColor;
        riskReasons.push(`🟡 Baja tasa de completado: ${completionRate.toFixed(1)}%`);
    }
    
    if (riskReasons.length === 0) {
        riskReasons.push('✅ Proyecto en buen estado');
    }
    
    // Predicción de fecha de finalización
    const today = new Date();
    let predictedEndDate = new Date(today);
    
    if (progressRate > 0) {
        const remainingProgress = 100 - progressRate;
        const daysToComplete = Math.ceil((remainingProgress / progressRate) * 30); // Estimación simple
        predictedEndDate.setDate(today.getDate() + daysToComplete);
    } else {
        predictedEndDate.setDate(today.getDate() + 60); // Estimación por defecto
    }
    
    const formattedDate = predictedEndDate.toLocaleDateString('es-ES', {
        weekday: 'long',
        year: 'numeric',
        month: 'long',
        day: 'numeric'
    });
    
    // Crear modal de resultados
    const overlay = document.createElement('div');
    overlay.className = 'executive-overlay';
    overlay.style.cssText = `
        position: fixed;
        top: 0;
        left: 0;
        right: 0;
        bottom: 0;
        background: rgba(0, 0, 0, 0.85);
        backdrop-filter: blur(10px);
        z-index: 1000000;
        display: flex;
        align-items: center;
        justify-content: center;
        padding: 20px;
    `;
    
    const modal = document.createElement('div');
    modal.style.cssText = `
        background: linear-gradient(135deg, #0a0a1a 0%, #121230 100%);
        border-radius: 24px;
        padding: 30px;
        width: 500px;
        max-width: 90vw;
        max-height: 80vh;
        overflow-y: auto;
        border: 2px solid ${riskColor}40;
        box-shadow: 0 20px 50px rgba(0,0,0,0.5);
        color: white;
    `;
    
    modal.innerHTML = `
        <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 25px;">
            <div>
                <h2 style="margin: 0 0 10px 0; color: white; display: flex; align-items: center; gap: 10px;">
                    <span style="color: ${riskColor};">🤖</span> 
                    Análisis Predictivo IA
                </h2>
                <p style="color: #95a5a6; margin: 0; font-size: 14px;">
                    ${currentProject.name}
                </p>
            </div>
            <button onclick="this.closest('.executive-overlay').remove()" style="
                background: rgba(231, 76, 60, 0.2);
                border: 1px solid #e74c3c;
                color: #e74c3c;
                padding: 8px 16px;
                border-radius: 6px;
                cursor: pointer;
                font-weight: bold;
                font-size: 14px;
            ">
                ✕ Cerrar
            </button>
        </div>
        
        <!-- Indicador de Riesgo -->
        <div style="
            background: ${riskColor}15;
            border: 2px solid ${riskColor}30;
            border-radius: 12px;
            padding: 20px;
            margin-bottom: 20px;
            text-align: center;
        ">
            <div style="font-size: 14px; color: #95a5a6; margin-bottom: 8px;">NIVEL DE RIESGO</div>
            <div style="font-size: 32px; font-weight: bold; color: ${riskColor}; margin-bottom: 10px;">
                ${riskLevel}
            </div>
            <div style="font-size: 12px; color: #95a5a6;">
                ${riskReasons.join(' • ')}
            </div>
        </div>
        
        <!-- Métricas Principales -->
        <div style="display: grid; grid-template-columns: repeat(2, 1fr); gap: 15px; margin-bottom: 20px;">
            <div style="
                background: rgba(46, 204, 113, 0.1);
                border: 1px solid rgba(46, 204, 113, 0.3);
                border-radius: 10px;
                padding: 15px;
                text-align: center;
            ">
                <div style="color: #2ecc71; font-size: 24px; font-weight: bold;">${completedTasks}</div>
                <div style="color: #95a5a6; font-size: 12px;">Completadas</div>
            </div>
            
            <div style="
                background: rgba(243, 156, 18, 0.1);
                border: 1px solid rgba(243, 156, 18, 0.3);
                border-radius: 10px;
                padding: 15px;
                text-align: center;
            ">
                <div style="color: #f39c12; font-size: 24px; font-weight: bold;">${inProgressTasks}</div>
                <div style="color: #008090; font-size: 12px;">En Progreso</div>
            </div>
            
            <div style="
                background: rgba(52, 152, 219, 0.1);
                border: 1px solid rgba(52, 152, 219, 0.3);
                border-radius: 10px;
                padding: 15px;
                text-align: center;
            ">
                <div style="color: #3498db; font-size: 24px; font-weight: bold;">${pendingTasks}</div>
                <div style="color: #95a5a6; font-size: 12px;">Pendientes</div>
            </div>
            
            <div style="
                background: rgba(231, 76, 60, 0.1);
                border: 1px solid rgba(231, 76, 60, 0.3);
                border-radius: 10px;
                padding: 15px;
                text-align: center;
            ">
                <div style="color: #e74c3c; font-size: 24px; font-weight: bold;">${criticalTasks}</div>
                <div style="color: #95a5a6; font-size: 12px;">Críticas</div>
            </div>
        </div>
        
        <!-- Predicción de Finalización -->
        <div style="
            background: rgba(155, 89, 182, 0.1);
            border: 1px solid rgba(155, 89, 182, 0.3);
            border-radius: 12px;
            padding: 20px;
            margin-bottom: 20px;
        ">
            <div style="color: #9b59b6; font-size: 14px; font-weight: bold; margin-bottom: 10px; display: flex; align-items: center; gap: 10px;">
                <span>📅</span> Predicción de Finalización
            </div>
            <div style="color: white; font-size: 18px; font-weight: bold; text-align: center; margin-bottom: 10px;">
                ${formattedDate}
            </div>
            <div style="color: #95a5a6; font-size: 12px; text-align: center;">
                Basado en la velocidad actual: ${progressRate.toFixed(1)}% de progreso
            </div>
        </div>
        
        <!-- Recomendaciones -->
        <div style="
            background: rgba(52, 152, 219, 0.1);
            border: 1px solid rgba(52, 152, 219, 0.3);
            border-radius: 12px;
            padding: 20px;
        ">
            <div style="color: #3498db; font-size: 14px; font-weight: bold; margin-bottom: 15px; display: flex; align-items: center; gap: 10px;">
                <span>💡</span> Recomendaciones IA
            </div>
            <div style="color: #95a5a6; font-size: 13px; line-height: 1.6;">
                ${getAIRecommendations(tasks, riskLevel, completionRate, criticalTasks)}
            </div>
        </div>
        
        <!-- Pie del modal -->
        <div style="margin-top: 25px; padding-top: 15px; border-top: 1px solid rgba(255,255,255,0.1); color: #95a5a6; font-size: 12px; text-align: center;">
            Análisis generado el ${new Date().toLocaleString()}
        </div>
    `;
    
    overlay.appendChild(modal);
    document.body.appendChild(overlay);
    
    // Función para generar recomendaciones
    function getAIRecommendations(tasks, riskLevel, completionRate, criticalTasks) {
        let recommendations = [];
        
        if (completionRate < 30) {
            recommendations.push('🎯 <strong>Priorizar completado:</strong> Enfócate en terminar tareas pendientes para aumentar la tasa de completado.');
        }
        
        if (criticalTasks > 0) {
            recommendations.push(`🔥 <strong>Atención a tareas críticas:</strong> ${criticalTasks} tareas marcadas como críticas requieren revisión inmediata.`);
        }
        
        const tasksWithoutDeps = tasks.filter(t => !t.dependencies || t.dependencies.length === 0);
        if (tasksWithoutDeps.length > tasks.length * 0.7) {
            recommendations.push('🔗 <strong>Definir dependencias:</strong> Establece relaciones entre tareas para mejorar la planificación.');
        }
        
        const overdueTasks = tasks.filter(t => {
            if (!t.deadline) return false;
            const deadline = new Date(t.deadline);
            return deadline < new Date() && t.status !== 'completed';
        }).length;
        
        if (overdueTasks > 0) {
            recommendations.push(`⏰ <strong>Tareas atrasadas:</strong> ${overdueTasks} tareas han superado su fecha límite.`);
        }
        
        if (recommendations.length === 0) {
            recommendations.push('✅ <strong>Mantener el ritmo:</strong> El proyecto está progresando adecuadamente según los indicadores actuales.');
        }
        
        return recommendations.map(rec => `<div style="margin-bottom: 8px;">${rec}</div>`).join('');
    }
    
    console.log('✅ Análisis predictivo IA completado');
};


// Función para mostrar notificaciones (si no existe)
function showNotification(message, type = 'info') {
    const colors = {
        info: '#3498db',
        success: '#2ecc71',
        warning: '#f39c12',
        error: '#e74c3c'
    };
    
    const color = colors[type] || colors.info;
    
    // Eliminar notificaciones anteriores
    const oldNotification = document.getElementById('temp-notification');
    if (oldNotification) oldNotification.remove();
    
    // Crear nueva notificación
    const notification = document.createElement('div');
    notification.id = 'temp-notification';
    notification.style.cssText = `
        position: fixed;
        top: 20px;
        right: 20px;
        background: ${color};
        color: white;
        padding: 12px 20px;
        border-radius: 8px;
        box-shadow: 0 5px 15px rgba(0,0,0,0.3);
        z-index: 999999;
        font-weight: 500;
        animation: slideIn 0.3s ease-out;
    `;
    
    notification.textContent = message;
    document.body.appendChild(notification);
    
    // Remover después de 3 segundos
    setTimeout(() => {
        if (notification.parentNode) {
            notification.style.animation = 'slideOut 0.3s ease-out';
            setTimeout(() => notification.remove(), 300);
        }
    }, 3000);
}

// Agregar estilos de animación si no existen
if (!document.getElementById('notification-styles')) {
    const style = document.createElement('style');
    style.id = 'notification-styles';
    style.textContent = `
        @keyframes slideIn {
            from {
                transform: translateX(100%);
                opacity: 0;
            }
            to {
                transform: translateX(0);
                opacity: 1;
            }
        }
        
        @keyframes slideOut {
            from {
                transform: translateX(0);
                opacity: 1;
            }
            to {
                transform: translateX(100%);
                opacity: 0;
            }
        }
    `;
    document.head.appendChild(style);
}






