// 🗑️ FUNCIONES PARA ELIMINAR TRANSCRIPCIONES (AGREGADO MANUALMENTE)
// ============================================================================

window.eliminarTranscripcion = async function(id) {
    if (!confirm('¿Eliminar esta transcripción?')) return;
    
    console.log('🗑️ Eliminando transcripción:', id);
    
    try {
        const clienteId = localStorage.getItem('clienteId');
        const response = await fetch(`https://mi-sistema-proyectos-backend-4.onrender.com/api/transcripciones/${id}?clienteId=${clienteId}`, {
            method: 'DELETE'
        });
        
        const data = await response.json();
        console.log('📦 Respuesta:', data);
        
        if (data.success) {
            showNotification('✅ Transcripción eliminada');
            cargarTranscripciones();
        } else {
            showNotification('❌ Error: ' + (data.error || 'desconocido'), 'error');
        }
    } catch (error) {
        console.error('❌ Error:', error);
        showNotification('❌ Error de conexión', 'error');
    }
};

window.eliminarTodasTranscripciones = async function() {
    if (!confirm('¿Eliminar TODAS las transcripciones?\n\nEsta acción no se puede deshacer.')) return;
    
    console.log('🗑️ Eliminando todas las transcripciones');
    
    const clienteId = localStorage.getItem('clienteId');
    const response = await fetch(`https://mi-sistema-proyectos-backend-4.onrender.com/api/transcripciones?clienteId=${clienteId}`);
    const data = await response.json();
    
    if (!data.transcripciones || data.transcripciones.length === 0) {
        showNotification('📭 No hay transcripciones para eliminar');
        return;
    }
    
    let eliminadas = 0;
    let errores = 0;
    
    for (const t of data.transcripciones) {
        try {
            const delResponse = await fetch(`https://mi-sistema-proyectos-backend-4.onrender.com/api/transcripciones/${t._id}?clienteId=${clienteId}`, {
                method: 'DELETE'
            });
            const delData = await delResponse.json();
            if (delData.success) eliminadas++;
            else errores++;
        } catch (e) {
            errores++;
        }
    }
    
    showNotification(`✅ ${eliminadas} transcripciones eliminadas${errores > 0 ? `, ${errores} errores` : ''}`);
    cargarTranscripciones();
};

console.log('✅ Funciones de eliminación cargadas correctamente');




// ===== ACTUALIZAR CONTADORES DE COLUMNAS CON ANIMACIÓN =====
function actualizarContadoresColumnas() {
    // Definir las columnas y sus contenedores
    const columnas = [
        { id: 'pendingList', contadorId: 'pendingCount' },
        { id: 'inProgressList', contadorId: 'inProgressCount' },
        { id: 'completedList', contadorId: 'completedCount' },
        { id: 'overdueList', contadorId: 'overdueCount' }
    ];
    
    columnas.forEach(col => {
        const contenedor = document.getElementById(col.id);
        const contadorElement = document.getElementById(col.contadorId);
        
        if (!contenedor || !contadorElement) return;
        
        // Contar tareas en esta columna
        const numTareas = contenedor.children.length;
        const valorActual = parseInt(contadorElement.textContent) || 0;
        
        // Si el número cambió, animar
        if (numTareas !== valorActual) {
            contadorElement.textContent = numTareas;
            
            // Agregar clase de animación
            contadorElement.classList.add('changed');
            
            // Quitar la clase después de la animación
            setTimeout(() => {
                contadorElement.classList.remove('changed');
            }, 500);
        }
    });
}

// Llamar a esta función cada vez que cambien las tareas
// Por ejemplo, después de drag & drop o después de crear/eliminar tareas
document.addEventListener('taskMoved', actualizarContadoresColumnas);
document.addEventListener('taskCreated', actualizarContadoresColumnas);
document.addEventListener('taskDeleted', actualizarContadoresColumnas);

// También puedes llamarla manualmente cuando sea necesario




// ===== MEJORAR DRAG & DROP =====
function mejorarDragDrop() {
    // Seleccionar todas las tareas arrastrables
    const tareas = document.querySelectorAll('.task-card[draggable="true"]');
    
    tareas.forEach(tarea => {
        // Cuando empieza a arrastrar
        tarea.addEventListener('dragstart', function(e) {
            this.classList.add('dragging');
        });
        
        // Cuando termina de arrastrar
        tarea.addEventListener('dragend', function(e) {
            this.classList.remove('dragging');
            
            // Quitar efecto de drag-over de todas las columnas
            document.querySelectorAll('.kanban-column, #pendingList, #inProgressList, #completedList, #overdueList').forEach(col => {
                col.classList.remove('drag-over');
            });
        });
    });
    
    // Mejorar columnas (zonas de drop)
    const columnas = document.querySelectorAll('.kanban-column, #pendingList, #inProgressList, #completedList, #overdueList');
    
    columnas.forEach(columna => {
        columna.addEventListener('dragover', function(e) {
            e.preventDefault();
            this.classList.add('drag-over');
        });
        
        columna.addEventListener('dragleave', function() {
            this.classList.remove('drag-over');
        });
        
        columna.addEventListener('drop', function() {
            this.classList.remove('drag-over');
            
            // Actualizar contadores después del drop
            setTimeout(actualizarContadoresColumnas, 100);
        });
    });
}

// Llamar después de cada renderizado de tareas
document.addEventListener('tasksRendered', mejorarDragDrop);
// También puedes llamarla manualmente
mejorarDragDrop();





// ===== CREAR TOOLTIPS AUTOMÁTICOS PARA TAREAS =====
function agregarTooltipsATareas() {
    const tareas = document.querySelectorAll('.task-card');
    
    tareas.forEach(tarea => {
        // Extraer información de la tarea (esto depende de cómo tengas los datos)
        const titulo = tarea.querySelector('.task-title')?.textContent || 'Tarea';
        const prioridad = tarea.querySelector('.priority-badge')?.textContent || 'Media';
        const asignado = tarea.querySelector('.task-assignee')?.textContent?.replace('Asignado a:', '')?.trim() || 'No asignado';
        const fecha = tarea.querySelector('.task-deadline')?.textContent?.replace('Fecha límite:', '')?.trim() || 'Sin fecha';
        
        // Crear tooltip
        const tooltipText = `${titulo} | Prioridad: ${prioridad} | 👤 ${asignado} | 📅 ${fecha}`;
        tarea.setAttribute('data-tooltip', tooltipText);
    });
}

// Llamar después de renderizar tareas
document.addEventListener('tasksRendered', agregarTooltipsATareas);
agregarTooltipsATareas();








