// (Esta función REEMPLAZA la refreshCalendar existente)
window.refreshCalendar = function() {
  if (!window.calendarInstance) return;

  console.log('🔄 Refrescando calendario con animación...');

  const calendarEl = document.getElementById('calendar');
  if (!calendarEl) return;

  // Animación de fade out
  calendarEl.style.opacity = '0';
  calendarEl.style.transform = 'scale(0.98)';
  calendarEl.style.transition = 'all 0.3s ease';

  setTimeout(() => {
    try {
      window.calendarInstance.removeAllEvents();
      window.calendarInstance.addEventSource(getFilteredCalendarTasks());
      window.calendarInstance.render(); // Forzar render completo
      window.calendarInstance.updateSize();

      // Animación de fade in
      calendarEl.style.opacity = '1';
      calendarEl.style.transform = 'scale(1)';

      console.log('✅ Calendario refrescado con éxito');
    } catch (e) {
      console.error('❌ Error refrescando calendario:', e);
      calendarEl.style.opacity = '1';
      calendarEl.style.transform = '';
    }
  }, 300);
};

