// ================================================
// 🎯 INICIALIZAR EFECTOS CUANDO SE ACTIVA LA VISTA
// ================================================
document.addEventListener('DOMContentLoaded', () => {
  // Observar cuando se activa la vista de calendario
  const observer = new MutationObserver((mutations) => {
    mutations.forEach((mutation) => {
      if (mutation.type === 'attributes' && mutation.attributeName === 'class') {
        const calendarView = document.getElementById('calendarView');
        if (calendarView && calendarView.classList.contains('active')) {
          setTimeout(addCalendarHoverEffects, 1000);
        }
      }
    });
  });

  const calendarView = document.getElementById('calendarView');
  if (calendarView) {
    observer.observe(calendarView, { attributes: true });
  }
});




