// ================================================
// 🛠️ TOOLTIPS DEL CALENDARIO - VARIABLES Y FUNCIONES
// ================================================
let currentTooltip = null;
let tooltipTimeout = null;


// ✅ ESCAPE HTML - DEBE IR PRIMERO
function escapeHtml(text) {
    if (!text) return '';
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}

function showCalendarTooltip(event, taskData) {
    console.log('💬 showCalendarTooltip llamada para:', taskData?.name || taskData?.taskName);
    
    if (currentTooltip) {
        currentTooltip.remove();
        currentTooltip = null;
    }
    
    if (tooltipTimeout) {
        clearTimeout(tooltipTimeout);
        tooltipTimeout = null;
    }
    
    const tooltipHTML = buildTooltipHTML(taskData);
    
    const tooltip = document.createElement('div');
    tooltip.className = 'calendar-event-tooltip';
    tooltip.innerHTML = tooltipHTML;
    tooltip.style.cssText = `
        position: fixed;
        background: linear-gradient(135deg, #0a0a1a 0%, #121230 100%);
        border: 2px solid rgba(139, 92, 246, 0.5);
        border-radius: 20px;
        padding: 18px 20px;
        color: white;
        font-size: 13px;
        z-index: 1000000;
        max-width: 380px;
        min-width: 300px;
        box-shadow: 0 25px 50px -12px rgba(0,0,0,0.8);
        backdrop-filter: blur(12px);
        pointer-events: none;
        opacity: 0;
        transition: opacity 0.2s ease;
        font-family: 'Segoe UI', system-ui, sans-serif;
        line-height: 1.5;
    `;
    
    document.body.appendChild(tooltip);
    
    // Guardar datos para reposicionamiento
    tooltip._taskData = taskData;
    tooltip._lastEvent = event;
    
    // 🔥 FUNCIÓN DE POSICIONAMIENTO
    function positionTooltip() {
        const rect = event.target.getBoundingClientRect();
        const tooltipWidth = tooltip.offsetWidth;
        const tooltipHeight = tooltip.offsetHeight;
        const windowWidth = window.innerWidth;
        const windowHeight = window.innerHeight;
        
        let left = rect.right + 15;
        let top = rect.top + (rect.height / 2) - (tooltipHeight / 2);
        
        // Si no cabe a la derecha
        if (left + tooltipWidth > windowWidth - 20) {
            left = rect.left - tooltipWidth - 15;
        }
        
        // Nunca menos de 10px
        if (left < 10) left = 10;
        if (top < 10) top = 10;
        if (top + tooltipHeight > windowHeight - 10) {
            top = windowHeight - tooltipHeight - 10;
        }
        
        // Forzar tooltip a la derecha
tooltip.style.right = '20px';
tooltip.style.left = 'auto';
tooltip.style.top = `${top}px`;
    }
    
    positionTooltip();
    
    // 🔥 Escuchar cambios de tamaño de ventana y del sidebar
    const handleResize = () => {
        if (tooltip.parentNode) {
            positionTooltip();
        }
    };
    
    window.addEventListener('resize', handleResize);
    
    // Escuchar cambios en el sidebar (cuando se oculta/muestra)
    const sidebar = document.querySelector('aside');
    const observer = new MutationObserver(() => {
        setTimeout(handleResize, 50);
    });
    
    if (sidebar) {
        observer.observe(sidebar, { attributes: true, attributeFilter: ['class'] });
    }
    
    // Guardar para limpiar después
    tooltip._resizeHandler = handleResize;
    tooltip._sidebarObserver = observer;
    
    currentTooltip = tooltip;
    
    setTimeout(() => {
        if (currentTooltip === tooltip) {
            tooltip.style.opacity = '1';
        }
    }, 10);
}

function hideCalendarTooltip() {
    if (currentTooltip) {
        // Limpiar event listeners
        if (currentTooltip._resizeHandler) {
            window.removeEventListener('resize', currentTooltip._resizeHandler);
        }
        if (currentTooltip._sidebarObserver) {
            currentTooltip._sidebarObserver.disconnect();
        }
        
        currentTooltip.style.opacity = '0';
        tooltipTimeout = setTimeout(() => {
            if (currentTooltip && currentTooltip.parentNode) {
                currentTooltip.remove();
                currentTooltip = null;
            }
            tooltipTimeout = null;
        }, 200);
    }
}
function buildTooltipHTML(task) {
    if (!task) return '<div>Sin información</div>';
    
    // Normalizar datos
    const taskName = task.name || task.taskName || 'Sin título';
    const taskId = task.id || task.taskId || 'N/A';
    const assignee = task.assignee || 'No asignado';
    const priority = task.priority || 'media';
    const progress = task.progress || 0;
    const estimatedTime = task.estimatedTime || 0;
    const timeLogged = task.timeLogged || 0;
    const description = task.description || '';
    const deadline = task.deadline;
    const status = task.status || 'pending';
    const daysRemaining = task.daysRemaining !== undefined ? task.daysRemaining : 
                          (deadline ? Math.ceil((new Date(deadline) - new Date()) / (1000 * 60 * 60 * 24)) : null);
    const isOverdue = task.isOverdue !== undefined ? task.isOverdue : 
                      (daysRemaining !== null && daysRemaining < 0 && status !== 'completed');
    
    // Colores según estado
    const statusColors = {
        'pending': '#f1c40f',
        'inProgress': '#008090',
        'completed': '#2ecc71',
        'overdue': '#e74c3c'
    };
    const statusColor = statusColors[status] || '#95a5a6';
    
    // Texto de estado
    const statusText = {
        'pending': 'Pendiente',
        'inProgress': 'En Progreso',
        'completed': 'Completada',
        'overdue': 'Rezagada'
    }[status] || status;
    
    // Color de prioridad
    const priorityColor = priority === 'alta' ? '#e74c3c' : 
                          priority === 'media' ? '#f39c12' : '#95a5a6';
    const priorityText = priority === 'alta' ? 'Alta' : 
                         priority === 'media' ? 'Media' : 'Baja';
    
    // Formatear fecha
    const formattedDeadline = deadline ? new Date(deadline).toLocaleDateString('es-ES', {
        day: '2-digit',
        month: 'short',
        year: 'numeric'
    }) : 'No definida';
    
    return `
        <div style="min-width: 280px;">
            <!-- Header -->
            <div style="display: flex; align-items: center; gap: 12px; margin-bottom: 15px; padding-bottom: 12px; border-bottom: 1px solid rgba(139, 92, 246, 0.3);">
                <div style="width: 40px; height: 40px; background: linear-gradient(135deg, #8b5cf6, #6d28d9); border-radius: 12px; display: flex; align-items: center; justify-content: center; font-size: 20px;">📋</div>
                <div style="flex: 1;">
                    <div style="font-weight: 700; font-size: 16px; color: white;">${escapeHtml(taskName)}</div>
                    <div style="color: #94a3b8; font-size: 11px;">ID: ${taskId}</div>
                </div>
            </div>
            
            <!-- Badges -->
            <div style="display: flex; gap: 12px; margin-bottom: 15px;">
                <div style="background: ${statusColor}20; border: 1px solid ${statusColor}; color: ${statusColor}; padding: 4px 12px; border-radius: 20px; font-size: 12px; font-weight: 600;">
                    ${statusText}
                </div>
                <div style="background: ${priorityColor}20; border: 1px solid ${priorityColor}; color: ${priorityColor}; padding: 4px 12px; border-radius: 20px; font-size: 12px; font-weight: 600;">
                    ${priorityText}
                </div>
            </div>
            
            <!-- Info principal -->
            <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 12px; margin-bottom: 15px;">
                <div style="background: rgba(255,255,255,0.05); padding: 8px 12px; border-radius: 8px;">
                    <div style="color: #94a3b8; font-size: 11px;">ASIGNADO A</div>
                    <div style="color: white; font-weight: 500; font-size: 14px;">${escapeHtml(assignee)}</div>
                </div>
                <div style="background: rgba(255,255,255,0.05); padding: 8px 12px; border-radius: 8px;">
                    <div style="color: #94a3b8; font-size: 11px;">PROGRESO</div>
                    <div style="color: white; font-weight: 500; font-size: 14px;">${progress}%</div>
                </div>
            </div>
            
            <!-- Fecha límite -->
            <div style="margin-bottom: 15px;">
                <div style="background: rgba(255,255,255,0.05); padding: 8px 12px; border-radius: 8px;">
                    <div style="color: #94a3b8; font-size: 11px;">FECHA LÍMITE</div>
                    <div style="color: white; font-weight: 500; font-size: 14px;">${formattedDeadline}</div>
                </div>
            </div>
            
            <!-- Tiempo -->
            <div style="display: flex; justify-content: space-between; background: rgba(0,0,0,0.3); padding: 12px; border-radius: 8px; margin-bottom: 12px;">
                <div>
                    <div style="color: #94a3b8; font-size: 11px;">ESTIMADO</div>
                    <div style="color: #f39c12; font-weight: 600;">${estimatedTime}h</div>
                </div>
                <div>
                    <div style="color: #94a3b8; font-size: 11px;">REGISTRADO</div>
                    <div style="color: #10b981; font-weight: 600;">${timeLogged}h</div>
                </div>
            </div>
            
            <!-- Estado de plazo -->
            ${daysRemaining !== null ? `
                <div style="background: ${isOverdue ? 'rgba(239,68,68,0.2)' : 'rgba(16,185,129,0.2)'}; padding: 10px; border-radius: 10px; text-align: center; border: 1px solid ${isOverdue ? '#ef4444' : '#10b981'}; margin-bottom: 12px;">
                    <span style="color: ${isOverdue ? '#ef4444' : '#10b981'}; font-weight: 700;">
                        ${isOverdue ? `⚠️ ATRASADA (${Math.abs(daysRemaining)} días)` : `✅ ${daysRemaining} días restantes`}
                    </span>
                </div>
            ` : ''}
            
            <!-- Descripción -->
            ${description ? `
                <div style="background: rgba(255,255,255,0.03); padding: 10px; border-radius: 8px; border-left: 3px solid #8b5cf6;">
                    <div style="color: #94a3b8; font-size: 11px; margin-bottom: 5px;">DESCRIPCIÓN</div>
                    <div style="color: #cbd5e1; font-size: 12px; line-height: 1.4;">${escapeHtml(description.substring(0, 100))}${description.length > 100 ? '...' : ''}</div>
                </div>
            ` : ''}
            
            <div style="margin-top: 12px; padding-top: 10px; border-top: 1px solid rgba(255,255,255,0.1); display: flex; justify-content: space-between;">
                <span style="color: #8b5cf6; font-size: 11px;">✨ Haz clic para editar</span>
                <span style="color: #94a3b8; font-size: 10px;">📅 ${new Date().toLocaleDateString()}</span>
            </div>
        </div>
    `;
}

// Función auxiliar para escapar HTML
function escapeHtml(text) {
    if (!text) return '';
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}





// ================================================
// 🚀 FUNCIÓN PARA FORZAR ACTUALIZACIÓN DEL CALENDARIO
// ================================================

function forceRefreshCalendar() {
    if (!window.calendarInstance) {
        console.log('⚠️ No hay instancia de calendario activa, recreando...');
        renderCalendar();
        return;
    }
    
    const calendarView = document.getElementById('calendarView');
    if (!calendarView || !calendarView.classList.contains('active')) {
        console.log('⏳ Calendario no visible, omitiendo actualización');
        return;
    }
    
    console.log('🔄 Actualizando calendario automáticamente...');
    
    try {
        // Obtener eventos actualizados
        const updatedEvents = getFilteredCalendarTasks();
        console.log('📊 Eventos actualizados:', updatedEvents.length);
        
        // Eliminar todos los eventos
        window.calendarInstance.removeAllEvents();
        
        // Agregar eventos actualizados UNO POR UNO para depuración
        updatedEvents.forEach((event, index) => {
            console.log(`   Agregando evento ${index + 1}: ${event.title} (${event.start} - ${event.end})`);
            window.calendarInstance.addEvent(event);
        });
        
        // Forzar render
        window.calendarInstance.render();
        
        // Verificar resultado
        setTimeout(() => {
            const eventsAfter = window.calendarInstance.getEvents();
            console.log('✅ Eventos después de actualizar:', eventsAfter.length);
            if (eventsAfter.length === 0 && updatedEvents.length > 0) {
                console.error('❌ Los eventos NO se agregaron correctamente. Verifica la estructura de los eventos.');
                console.log('📋 Primer evento ejemplo:', updatedEvents[0]);
            }
        }, 200);
        
    } catch (error) {
        console.error('❌ Error actualizando calendario:', error);
        // Fallback: recrear calendario
        renderCalendar();
    }
}


